CREATE OR ALTER FUNCTION [SCore].[tvf_PropertiesForEntityType]
	(
		@Guid UNIQUEIDENTIFIER,
		@UserId INT
	)
RETURNS TABLE 
AS
RETURN SELECT		p.RowStatus,
