CREATE OR ALTER FUNCTION [SCore].[tvf_ProjectDirectory] 
(
    @UserId INT,
    @ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
AS
RETURN 
SELECT  pd.ID,
        pd.RowStatus, 
        pd.RowVersion,
        pd.Guid,
		pdr.Name AS Role,
		c.DisplayName AS Contact
FROM    SJob.ProjectDirectory pd
JOIN	SJob.Jobs j ON (j.ID = pd.JobID)
JOIN	SCrm.Accounts a ON (a.ID = pd.AccountID)
JOIN	SJob.ProjectDirectoryRoles pdr ON (pdr.ID = pd.ProjectDirectoryRoleID)
JOIN	SCrm.Contacts c ON (c.ID = pd.ContactID)
WHERE   (pd.RowStatus  NOT IN (0, 254))
    AND (j.Guid = @ParentGuid)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(pd.Guid, @UserId) oscr
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SCore].[tvf_ScheduleItems]
--
GO
CREATE OR ALTER FUNCTION [SCore].[tvf_ScheduleItems] 
(
    @UserId INT,
    @CurrentUserOnly bit
)
RETURNS TABLE
AS
RETURN  
SELECT      a.ID,
            a.Guid,
            j.Number as JobNumber,
            a.[Date] as [Start],
            a.EndDate as [End],
            a.Title,
            a.Notes as [Description],
            CAST(0 as BIT) as IsAllDay,
            N'' as RecurrenceRule,
            0 as RecurrenceId,
            N'' as RecurrenceExceptions,
            N'' as StartTimezone,
            N'' as EndTimezone,
            a.SurveyorID as UserId,
            a.ActivityStatusID as StatusId,
            a.ActivityTypeID as TypeId
FROM        SJob.Activities a
JOIN		SJob.Jobs j ON (j.ID = a.JobID)
WHERE       (a.RowStatus NOT IN (0, 254))
        AND (EXISTS 
				(SELECT	1
				FROM	SJob.ActivityTypes t
				WHERE	(t.IsScheduleItem = 1)
					AND	(t.Id = a.ActivityTypeID)
				)
			)
		AND	(
				(@CurrentUserOnly = 0)
				OR (
						(@CurrentUserOnly = 1)
					AND	(a.SurveyorID = @UserId)
				)
			)
		AND	(EXISTS
			(				
	SELECT
			1
	FROM
			SCore.ObjectSecurityForUser_CanRead(a.Guid, @UserId) oscr
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

