--
-- Remove Schema Binding option from [SSop].[tvf_EnquiryServices]
--
GO





CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiryServices]
(
	@UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
AS RETURN	
SELECT  es.ID,
        es.RowStatus,
        es.RowVersion,
        es.Guid,
		jt.Name AS JobType,
		q.FullNumber AS Quote,
		esei.QuoteNet, 
		CONCAT(srs.Number, N' - ', srs.Description) AS StartRibaStage,
		CONCAT(ers.Number, N' - ', ers.Description) AS EndRibaStage,
		CASE 
			WHEN q.ID < 0 THEN N'No Quote'
			WHEN q.DateDeclinedToQuote IS NOT NULL THEN N'Declined To Quote.' --NEW [CBLD-592]
			ELSE qcf.QuoteStatus END AS QuoteStatus
FROM    SSop.EnquiryServices es
JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id = es.ID)
JOIN	SSop.Quotes q ON (q.ID = esei.QuoteId)
JOIN	SSop.Quote_CalculatedFields AS qcf ON (qcf.ID = q.ID)
JOIN	SJob.JobTypes jt ON (jt.ID = es.JobTypeId)
JOIN	SJob.RibaStages srs ON (srs.ID = es.StartRibaStageId)
JOIN	SJob.RibaStages ers ON (ers.ID = es.EndRibaStageId)
JOIN	SSop.Enquiries enq ON (enq.ID = es.EnquiryId) --NEW [CBLD-592]
WHERE   (es.RowStatus NOT IN (0, 254))
	AND	(q.RowStatus NOT IN (0, 254))
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(es.Guid, @UserId) oscr
			)
		)
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.Enquiries AS e
				WHERE	(e.Guid = @ParentGuid)
					AND	(e.ID = es.EnquiryId)
			)
		)
UNION ALL
SELECT  -1,
        CONVERT(tinyint, 1),
        null,
        '00000000-0000-0000-0000-000000000000',
		N'Total:' AS JobType,
		N'' AS Quote,
		SUM(esei.QuoteNet) AS QuoteNet, 
		N'' AS StartRibaStage,
		N'' AS EndRibaStage,
		N'' AS QuoteStatus
FROM    SSop.EnquiryServices es
JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id = es.ID)
WHERE   (es.RowStatus NOT IN (0, 254))
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.Enquiries AS e
				WHERE	(e.Guid = @ParentGuid)
					AND	(e.ID = es.EnquiryId)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SSop].[tvf_OpenEnquiries]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_OpenEnquiries]
(
	@UserId INT
)
RETURNS TABLE
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		CASE WHEN e.Revision = 0 THEN e.Number ELSE (e.Number + N' (' + CONVERT(NVARCHAR(2), e.Revision) + N') ') END AS Number,
		e.QuotingDeadlineDate,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		ecf.EnquiryStatus
FROM    SSop.Enquiries e
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)
	AND	(e.DeclinedToQuoteDate IS NULL)
	AND	(EXISTS
			(
				SELECT	1
				FROM	SSop.EnquiryServices es 
				WHERE	(es.EnquiryId = e.ID)
					AND	(es.RowStatus NOT IN (0, 254))
					AND	(es.QuoteId < 0)
			)
		)
	AND	(e.Date > DATEADD(MONTH, -6, GETDATE()))
GO
