CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteItems]
(
	@UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
AS RETURN	
SELECT  qi.ID,
        qi.RowStatus,
        qi.Guid,
		qi.SortOrder,
		qi.Details,
		p.Code,
		qi.Quantity,
		qi.Net,
		qit.Vat,
		qit.Gross,
		qit.LineNet,
		qit.LineVat,
		qit.LineGross
FROM    SSop.QuoteItems qi
JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
JOIN	SProd.Products p ON (p.ID = qi.ProductId)	
WHERE   (qi.RowStatus NOT IN (0, 254))
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(qi.Guid, @UserId) oscr
			)
		)
	AND	(q.Guid = @ParentGuid)
UNION ALL 
SELECT	-2,
		1,
		'00000000-0000-0000-0000-000000000000',
		999,
		N'Total',
		N'',
		SUM(qi.Quantity),
		SUM(qi.Net),
		SUM(qit.Vat),
		SUM(qit.Gross),
		SUM(qit.LineNet),
		SUM(qit.LineVat),
		SUM(qit.LineGross)
FROM    SSop.QuoteItems qi
JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
WHERE   (qi.RowStatus NOT IN (0, 254))
	AND	(q.Guid = @ParentGuid)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

