--
-- Remove Schema Binding option from [SJob].[JobStatus]
--
GO







CREATE OR ALTER VIEW [SJob].[JobStatus]
AS 
SELECT	j.ID,
		CASE 
			WHEN (j.JobCompleted IS NOT NULL) THEN N'Completed'
			WHEN (j.JobCancelled IS NOT NULL) THEN N'Cancelled'
			WHEN (j.DeadDate IS NOT NULL) THEN N'Dead'
			WHEN (j.JobDormant IS NOT NULL) THEN N'Dormant'
			WHEN (j.ReviewedDateTimeUTC IS NOT NULL) THEN N'Reviewed'
			WHEN (j.IsCompleteForReview = 1) THEN N'Complete for Review'
			WHEN ((j.JobStarted IS NOT NULL) AND (j.JobCompleted IS NULL) AND (j.JobCancelled IS NULL) AND (j.JobDormant IS NULL) AND (j.IsCompleteForReview = 0) AND (j.ReviewedDateTimeUTC IS NULL) AND (j.DeadDate IS NULL)) THEN N'Live'
			WHEN (j.JobStarted IS NULL) THEN N'Not Started'
			ELSE N'Unknown'
		END AS JobStatus,
		p.IsSubjectToNDA
FROM	SJob.Jobs j
JOIN	SSop.Projects AS p ON (p.ID = j.ProjectId)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SJob].[GetJobSignatoryInfo]
--
GO
CREATE OR ALTER VIEW [SJob].[GetJobSignatoryInfo]
AS
SELECT		j.ID,
			j.RowStatus,
			j.RowVersion,
			ISNULL (   QuoteDetail.EnquiryGuid,
					   '00000000-0000-0000-0000-000000000000'
				   ) AS EnquiryGuid,
			ISNULL (   QuoteDetail.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   ) AS QuoteGuid,
			j.Guid	 AS JobGuid,
			jt.Name JobTypeName,
			QuoteDetail.FullName,
			QuoteDetail.UserGuid,
			QuoteDetail.EmailAddress,
			QuoteDetail.JobTitle,
			QuoteDetail.IsActive,
			ISNULL (   QuoteDetail.Signature,
					   0x
				   ) AS BinarySignature
FROM		SJob.Jobs AS j
JOIN		SJob.JobTypes		 AS jt ON (jt.ID = j.JobTypeId)
OUTER APPLY
			(
				SELECT	q.ID,
						q.Guid,
						q.EnquiryServiceID,
						e.Guid AS EnquiryGuid,
						i.Guid AS UserGuid,
						i.EmailAddress,
						i.JobTitle,
						i.FullName,
						I.IsActive,
						i.Signature
				FROM	SSop.Quotes AS q
				LEFT JOIN	SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
				LEFT JOIN	SSop.Enquiries		 AS e ON (e.ID	 = es.EnquiryId) 
				LEFT JOIN	SCore.Identities	 AS i ON (i.ID	 = e.SignatoryIdentityId)
				WHERE	(EXISTS
					(
						SELECT	1
						FROM	SSop.QuoteItems AS qi
						WHERE	(qi.QuoteId		 = q.ID)
							AND (qi.CreatedJobId = j.ID)
					)
						)
			)		  AS QuoteDetail
;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

