--
-- Remove Schema Binding option from [SJob].[JobMilestoneMetric]
--
GO





CREATE OR ALTER VIEW [SJob].[JobMilestoneMetric]
AS
SELECT	j.ID,
		j.Guid,
		ISNULL(FirstDataPoint.SortOrder, 1) AS FirstValue,
		ISNULL(LEFT(FirstDataPoint.Name, 10), N'') AS FirstDescription,
		ISNULL(FirstDataPoint.Complete, 0) AS FirstComplete,
		ISNULL(PreviousDataPoint.SortOrder, 2) AS PreviousValue,
		ISNULL(LEFT(PreviousDataPoint.Name, 10), N'') AS PreviousDescription,
		ISNULL(PreviousDataPoint.Complete, 0) AS PreviousComplete,
		ISNULL(MidDataPoint.SortOrder, 3)  AS MidValue,
		ISNULL(LEFT(MidDataPoint.Name, 10), N'') AS MidDescription,
		ISNULL(MidDataPoint.Complete, 0) AS MidComplete,
		ISNULL(NextDataPoint.SortOrder, 4) AS NextValue,
		ISNULL(LEFT(NextDataPoint.Name, 10), N'') AS NextDescription,
		ISNULL(NextDataPoint.Complete, 0) AS NextComplete,
		ISNULL(LastDataPoint.SortOrder, 5) AS LastValue,
		ISNULL(LEFT(LastDataPoint.Name, 10), N'') AS LastDescription,
		ISNULL(LastDataPoint.Complete, 0) AS LastComplete
FROM	SJob.Jobs j
OUTER APPLY 
(
	SELECT	jm.SortOrder
	FROM	SJob.Milestones jm
	WHERE	(jm.JobID = j.ID)
		AND (jm.RowStatus NOT IN (0, 254))	
		AND (
				(
					((jm.CompletedDateTimeUTC IS NULL) OR (jm.IsNotApplicable = 0))
				AND	(NOT EXISTS
						(
							SELECT	1
							FROM	SJob.Milestones jm2
							WHERE	(jm2.JobID = jm.JobID)
								AND (jm2.RowStatus NOT IN (0, 254))	
								AND ((jm2.CompletedDateTimeUTC IS NULL) OR (jm2.IsNotApplicable = 0))
								AND	(jm2.SortOrder < jm.SortOrder)
						)
					)
				)
				OR 
				(
					((jm.CompletedDateTimeUTC IS NOT NULL) OR (jm.IsNotApplicable = 1))
				AND	(NOT EXISTS
						(
							SELECT	1
							FROM	SJob.Milestones jm2
							WHERE	(jm2.JobID = jm.JobID)
								AND (jm2.RowStatus NOT IN (0, 254))	
								AND ((jm2.CompletedDateTimeUTC IS NOT NULL) OR (jm2.IsNotApplicable = 1))
								AND	(jm2.SortOrder < jm.SortOrder)
						)
					)
				)
			)

) AS CurrentDataPoint
OUTER APPLY
(
	SELECT	jm.SortOrder,
			mt.Name,
			CONVERT(BIT, CASE WHEN jm.CompletedDateTimeUTC IS NOT NULL OR jm.IsNotApplicable = 1 THEN 1 ELSE 0 END) AS Complete
	FROM	SJob.Milestones jm
	JOIN	SJob.MilestoneTypes mt ON (mt.ID = jm.MilestoneTypeID)
	WHERE	(jm.SortOrder = 1)
		AND	(jm.JobID = j.ID)
		AND (jm.RowStatus NOT IN (0, 254))
) AS FirstDataPoint
OUTER APPLY
(
	SELECT	jm.SortOrder,
			mt.Name,
			CONVERT(BIT, CASE WHEN jm.CompletedDateTimeUTC IS NOT NULL OR jm.IsNotApplicable = 1 THEN 1 ELSE 0 END) AS Complete
	FROM	SJob.Milestones jm
	JOIN	SJob.MilestoneTypes mt ON (mt.ID = jm.MilestoneTypeID)
	WHERE	(jm.JobID = j.ID)
		AND (jm.RowStatus NOT IN (0, 254))
		AND	(
				((jm.SortOrder = 3) AND (CurrentDataPoint.SortOrder <= 3))
				OR ((jm.SortOrder = CurrentDataPoint.SortOrder) AND (CurrentDataPoint.SortOrder > 3))
			)
) AS MidDataPoint
OUTER APPLY
(
	SELECT	jm.SortOrder,
			mt.Name,
			CONVERT(BIT, CASE WHEN jm.CompletedDateTimeUTC IS NOT NULL OR jm.IsNotApplicable = 1 THEN 1 ELSE 0 END) AS Complete
	FROM	SJob.Milestones jm
	JOIN	SJob.MilestoneTypes mt ON (mt.ID = jm.MilestoneTypeID)
	WHERE	(jm.JobID = j.ID)
		AND (jm.RowStatus NOT IN (0, 254))
		AND (
				((CurrentDataPoint.SortOrder > 2) AND (jm.SortOrder = CurrentDataPoint.SortOrder - 1))
				OR ((CurrentDataPoint.SortOrder < 3) AND (jm.SortOrder = 2))
			)
) AS PreviousDataPoint
OUTER APPLY
(
	SELECT	jm.SortOrder,
			mt.Name,
			CONVERT(BIT, CASE WHEN jm.CompletedDateTimeUTC IS NOT NULL OR jm.IsNotApplicable = 1 THEN 1 ELSE 0 END) AS Complete
	FROM	SJob.Milestones jm
	JOIN	SJob.MilestoneTypes mt ON (mt.ID = jm.MilestoneTypeID)
	WHERE	(jm.JobID = j.ID)
		AND (jm.RowStatus NOT IN (0, 254))
		AND (
				((CurrentDataPoint.SortOrder <=3) AND (jm.SortOrder = 4))
				OR ((CurrentDataPoint.SortOrder > 3) AND (jm.SortOrder = CurrentDataPoint.SortOrder + 1))
			)
) AS NextDataPoint
OUTER APPLY
(
	SELECT	jm.SortOrder,
			mt.Name,
			CONVERT(BIT, CASE WHEN jm.CompletedDateTimeUTC IS NOT NULL OR jm.IsNotApplicable = 1 THEN 1 ELSE 0 END) AS Complete
	FROM	SJob.Milestones jm
	JOIN	SJob.MilestoneTypes mt ON (mt.ID = jm.MilestoneTypeID)
	WHERE	(jm.JobID = j.ID)
		AND (jm.RowStatus NOT IN (0, 254))
		AND	(NOT EXISTS 
				(
					SELECT	1
					FROM	SJob.Milestones jm2 
					WHERE	(jm2.JobID = jm.JobID)
						AND	(jm2.RowStatus NOT IN (0, 254))
						AND (jm2.SortOrder > jm.SortOrder)
				)
			)
) AS LastDataPoint
WHERE	(j.RowStatus NOT IN (0, 254))
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SJob].[CurrentScheduledWork]
--
GO

CREATE OR ALTER FUNCTION [SJob].[CurrentScheduledWork]
(
	@UserId INT
)
RETURNS TABLE
AS RETURN
SELECT	j.ID,
		j.Guid,
		a.RowVersion,
		a.RowStatus,
		j.Number AS JobNumber,
		client.Name AS ClientName,
		prop.FormattedAddressComma AS PropertyAddress,
		a.Date AS StartDateTime,
		a.EndDate AS EndDateTime,
		a.Title ActivityTitle,
		aty.Name   AS ActivityType,
		ast.Name   AS ActivityStatus,
		i.FullName AS SurveyorName,
		ast.SortOrder AS SortPriority
FROM	SJob.Activities		AS a
JOIN	SJob.ActivityStatus AS ast ON (ast.ID = a.ActivityStatusID)
JOIN	SJob.ActivityTypes	AS aty ON (aty.ID = a.ActivityTypeID)
JOIN	SJob.Jobs			AS j ON (j.ID	  = a.JobID)
JOIN	SJob.Assets prop ON (prop.ID = j.UprnID)
JOIN	SCrm.Accounts client ON (client.ID = j.ClientAccountID)
JOIN	SCore.Identities	AS i ON (i.ID	  = a.SurveyorID)
WHERE	(aty.IsScheduleItem = 1)
	AND (a.SurveyorID = @UserId)
	AND	(a.Date BETWEEN DATEADD (DAY, -7, GETUTCDATE()) AND DATEADD (DAY, +7, GETUTCDATE()))
	AND (a.RowStatus NOT IN (0, 254))

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SJob].[MyWork_Activities]
--
GO
CREATE OR ALTER FUNCTION [SJob].[MyWork_Activities]
(
	@UserId INT
)
RETURNS TABLE
AS RETURN
SELECT	a.ID,
		a.Guid,
		a.RowVersion,
		a.RowStatus,
		a.Date,
		a.EndDate,
		a.Title,
		aty.Name   AS ActivityType,
		ast.Name   AS ActivityStatus,
		i.FullName AS SurveyorName,
		j.Number   AS JobNumber,
		CONVERT(NVARCHAR(20), CASE WHEN (EXISTS (SELECT 1 FROM SFin.InvoiceRequestItems iri WHERE (iri.ActivityId = a.ID) AND (iri.RowStatus NOT IN (0, 254)))) THEN 1 ELSE 0 END) + N' / '
		+ CONVERT(NVARCHAR(20), CASE WHEN (EXISTS (SELECT 1 FROM SFin.TransactionDetails td WHERE (td.ActivityId = a.ID) AND (td.RowStatus NOT IN (0, 254)))) THEN 1 ELSE 0 END) AS RequestedInvoiced
FROM	SJob.Activities		AS a
JOIN	SJob.ActivityStatus AS ast ON (ast.ID = a.ActivityStatusID)
JOIN	SJob.ActivityTypes	AS aty ON (aty.ID = a.ActivityTypeID)
JOIN	SJob.Jobs			AS j ON (j.ID	  = a.JobID)
JOIN	SCore.Identities	AS i ON (i.ID	  = a.SurveyorID)
WHERE	(a.SurveyorID = @UserId)
	AND	(a.Date BETWEEN DATEADD (	WEEK,
									-1,
									DATEADD (	WEEK,
												DATEDIFF (	 WEEK,
															 0,
															 GETDATE ()
														 ),
												0
											)
								) AND DATEADD (	  WEEK,
												  1,
												  DATEADD (	  WEEK,
															  DATEDIFF (   WEEK,
																		   0,
																		   GETDATE ()
																	   ),
															  0
														  )
											  )
		)
	AND (a.RowStatus NOT IN (0, 254));


GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

