CREATE OR ALTER VIEW	[SSop].[Quote_ExtendedInfo]
AS
SELECT	q.Id,
		q.RowStatus,
		q.RowVersion,
		q.Guid,
		e.ID EnquiryID, 
		e.QuotingDeadlineDate,
		e.ClientAccountID,
		CASE WHEN q.ClientAddressId = -1 THEN e.ClientAddressId ELSE q.ClientAddressId END AS ClientAddressId,
		e.ClientAccountContactId,
		e.AgentAccountID,
		CASE WHEN q.AgentAddressId = -1 THEN e.AgentAddressId ELSE q.AgentAddressId END AS AgentAddressId,
		--ACForAgent.Guid AS AgentAccountContactId,
		CASE WHEN e.IsClientFinanceAccount = 1 THEN e.ClientAccountId ELSE e.FinanceAccountId END AS FinanceAccountId,
		CASE WHEN e.IsClientFinanceAccount = 1 THEN e.FinanceAddressId ELSE e.FinanceAddressId END AS FinanceAddressId,
		CASE WHEN e.IsClientFinanceAccount = 1 THEN e.FinanceContactId ELSE e.FinanceContactId END AS FinanceContactId,
		e.PropertyId,
		CASE WHEN q.DescriptionOfWorks = '' THEN e.DescriptionOfWorks ELSE q.DescriptionOfWorks END AS DescriptionOfWorks, --[CBLD-588]
		jt.Name AS JobType,
		jt.Guid AS JobTypeGuid,
		AC.Guid AS ClientContactId,
		e.AgentAccountContactId
FROM	SSop.Quotes q 
LEFT JOIN	SSop.EnquiryServices es ON (es.ID = q.EnquiryServiceID)
LEFT JOIN	SSop.Enquiries e ON (e.ID = es.EnquiryId)
LEFT JOIN	SJob.JobTypes AS jt ON (jt.ID = es.JobTypeId)
JOIN SCrm.AccountContacts AS AC ON (e.ClientAccountContactId = AC.ID)
JOIN SCrm.AccountContacts AS ACForAgent ON (e.AgentAccountContactId = ACForAgent.ID)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SSop].[Enquiry_CalculatedFields]
--
GO











CREATE OR ALTER VIEW [SSop].[Enquiry_CalculatedFields]
AS
SELECT	e.ID,
		CASE
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.QuoteItems AS qi 
											WHERE	(qi.QuoteId = q.ID)
												AND	(qi.CreatedJobId < 0)
												AND (qi.RowStatus NOT IN (0, 254))
										)
									)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = e.ID)
												AND (es2.RowStatus NOT IN (0, 254))
												AND	(q2.DateAccepted IS NULL)
												AND	(q2.DeadDate IS NULL)
												AND	(q2.DateRejected IS NULL)
										)
									)
					   )
				 ) THEN N'Complete'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND (es2.RowStatus NOT IN (0, 254))
												AND	(q2.DateAccepted IS NULL) 
												AND	(q2.DateRejected IS NULL)
												AND	(q2.DeadDate IS NULL)
										)
									)
					   )
				 ) THEN N'Accepted'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND (es2.RowStatus NOT IN (0, 254))
												AND	(q.DateAccepted IS NULL) 
										)
									)
					   )
				 ) THEN N'Part Accepted'

			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateRejected IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND (es2.RowStatus NOT IN (0, 254))
												AND	(q.DateRejected IS NULL) 
										)
									)
					   )
				 ) THEN N'Rejected'
			WHEN e.ChaseDate1 IS NOT NULL THEN N'1st Chase'
			WHEN e.ChaseDate2 IS NOT NULL THEN N'2nd Chase'
			WHEN (EXISTS
				   (
					   SELECT 1
					   FROM SSop.EnquiryServices es
					   WHERE es.EnquiryId = e.ID
					   AND es.RowStatus NOT IN (0,254) -- Ensure active enquiry services
					   AND (EXISTS
								(
									SELECT	1
									FROM	SSop.EnquiryServices m_es
									WHERE	(es.EnquiryId = m_es.EnquiryId)
										AND	(m_es.RowStatus NOT IN (0, 254))
										AND	(es.ID <> m_es.ID)
								)
							)
				   )
				   AND (EXISTS
					   (
						   SELECT 1
						   FROM SSop.Quotes q
						   JOIN SSop.EnquiryServices es ON q.EnquiryServiceID = es.ID
						   WHERE es.EnquiryId = e.ID
						   AND es.RowStatus NOT IN (0,254)
						   AND q.DateSent IS NOT NULL
					   )
				   )
				   AND (EXISTS
					   (
						   SELECT 1
						   FROM SSop.Quotes q2
						   JOIN SSop.EnquiryServices es2 ON q2.EnquiryServiceID = es2.ID
						   WHERE es2.EnquiryId = e.ID
						   AND es2.RowStatus NOT IN (0,254)
						   AND q2.DateSent IS NULL
						   AND q2.DateRejected IS NULL
						   AND q2.DateDeclinedToQuote IS NULL
					   )
				   )
			) THEN N'Part Sent'
					WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateSent IS NOT NULL)
					   )
				 ) THEN N'Sent'	
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
					   )
				 ) THEN N'Quoting'
			WHEN e.DeadDate IS NOT NULL THEN N'Dead'
			WHEN e.DeclinedToQuoteDate IS NOT NULL THEN N'Declined'
			WHEN e.IsReadyForQuoteReview = 1 THEN N'Ready for Quote'
			WHEN e.QuotingDeadlineDate < DATEADD(DAY, 2, GETDATE ()) THEN N'Deadline Approaching'
			WHEN e.QuotingDeadlineDate < GETDATE () THEN N'Deadline Missed'
			ELSE N'New'
		END AS EnquiryStatus
FROM	SSop.Enquiries AS e;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

