--
-- Create or alter function [SCore].[tvf_ObjectSecurityForObject]
--
GO
CREATE OR ALTER FUNCTION [SCore].[tvf_ObjectSecurityForObject]
	(
		@Guid UNIQUEIDENTIFIER,
		@UserId INT
	)
RETURNS TABLE
             --WITH SCHEMABINDING
AS
RETURN SELECT		os.ID,
					os.RowStatus,
					os.RowVersion,
					os.Guid,
					os.ObjectGuid,
					i.Guid AS UserGuid,
					i.FullName AS UserFullName,
					i.EmailAddress AS UserIdentity,
					g.Guid AS GroupGuid,
					g.Name AS GroupName,
					g.DirectoryId AS GroupIdentity,
					os.CanRead,
					os.DenyRead,
					os.CanWrite,
					os.DenyWrite
	   FROM			SCore.ObjectSecurity		  AS os
	   JOIN			SCore.Identities			  AS i ON (i.ID = os.UserId)
	   JOIN			SCore.Groups				AS g ON (g.ID = os.GroupId)  
	   WHERE		(os.ObjectGuid = @Guid)
				AND	(os.RowStatus NOT IN (0, 254))
	   UNION ALL 
	   SELECT	-1,
				1,
				g.RowVersion,
				'00000000-0000-0000-0000-000000000000',
				@Guid,
				'00000000-0000-0000-0000-000000000000' AS UserGuid,
				N'Everyone' AS UserFullName,
				N'Everyone' AS UserIdentity,
				g.Guid AS GroupGuid,
				g.Name AS GroupName,
				g.DirectoryId AS GroupIdentity,
				CONVERT(BIT, 1) AS CanRead,
				CONVERT(BIT, 0) AS DenyRead,
				CONVERT(BIT, 1) AS CanWrite,
				CONVERT(BIT, 0) AS DenyWrite
		FROM	SCore.Groups AS g
		WHERE	(g.ID = ((-1)))
			AND	(NOT EXISTS	
					(
						SELECT	1
						FROM	SCore.ObjectSecurity AS os 
						WHERE	(os.ObjectGuid = @Guid)
							AND	(os.RowStatus NOT IN (0, 254))
					)
				)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SCore].[ObjectSecurityForUser_CanRead]
--
GO
CREATE OR ALTER FUNCTION [SCore].[ObjectSecurityForUser_CanRead]
	(
		@ObjectGuid UNIQUEIDENTIFIER,
		@UserId INT
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN
	SELECT	1 AS CanRead
	FROM	SCore.Identities i
	WHERE	(i.ID = @UserId)
		AND	(NOT EXISTS
				(
					SELECT	1
					FROM	SCore.ObjectSecurity os1
					WHERE	(os1.ObjectGuid = @ObjectGuid)
						AND	(os1.DenyRead > 0)
						AND	(os1.RowStatus NOT IN (0, 254))
						AND (
								(os1.UserId = i.ID)
								OR 
								(EXISTS	
									(	
										SELECT 1
										FROM	SCore.UserGroups ug
										WHERE	(ug.IdentityID = i.ID)
											AND	(os1.GroupId = ug.GroupID)
											AND	(ug.RowStatus NOT IN (0, 254))
									)
								)
							)
				)
			)
		AND	(
				( EXISTS
					(
						SELECT	1
						FROM	SCore.ObjectSecurity os1
						WHERE	(os1.ObjectGuid = @ObjectGuid)
							AND	(os1.CanRead > 0)
							AND	(os1.RowStatus NOT IN (0, 254))
							AND (
								(os1.UserId = i.ID)
								OR 
								(EXISTS	
									(
										SELECT
												1
										FROM
												SCore.UserGroups ug
										WHERE
												(ug.IdentityID = i.ID)
												AND (os1.GroupId = ug.GroupId)
												AND (ug.RowStatus NOT IN (0, 254))
											)
								)
							)
					)
				)
			OR	(NOT EXISTS
					(
						SELECT	1
						FROM	SCore.ObjectSecurity hos3
						WHERE	(hos3.ObjectGuid = @ObjectGuid)
							AND (hos3.RowStatus NOT IN (0, 254))
					)
				)
			)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SCore].[ExpandedObjectSecurityForUser]
--
GO
CREATE OR ALTER FUNCTION [SCore].[ExpandedObjectSecurityForUser]
	(
		@ObjectGuid UNIQUEIDENTIFIER,
		@UserId		INT
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
	RETURN

	SELECT
			os.DenyRead,
			os.CanRead,
			os.CanWrite,
			os.DenyWrite
	FROM
			SCore.ObjectSecurity AS os
	WHERE
			(os.RowStatus NOT IN (0, 254))
			AND (os.ObjectGuid = @ObjectGuid)
			AND	(@UserId > 0)
			AND (
					(os.UserId = @UserId)
					OR (EXISTS
					(
						SELECT
								1
						FROM
								SCore.UserGroups AS ug
						JOIN
								SCore.Groups AS g ON (ug.GroupID = g.ID)
						WHERE
								(g.ID = os.GroupID)
								AND (g.ID > 0)
								AND (ug.IdentityID = @UserId)
								AND (ug.RowStatus NOT IN (0, 254))
								AND (g.RowStatus NOT IN (0, 254))
					)
					)
			)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SCore].[ObjectSecurityForUser]
--
GO
CREATE OR ALTER FUNCTION [SCore].[ObjectSecurityForUser]
	(
		@ObjectGuid UNIQUEIDENTIFIER,
		@UserId		INT
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
	RETURN
	SELECT
			@ObjectGuid AS ObjectGuid,
			CAST(CASE
					WHEN EXISTS
						(
							SELECT
									1
							FROM
									SCore.ExpandedObjectSecurityForUser(@ObjectGuid, @UserId) os1
							WHERE
									os1.DenyRead > 0
						) THEN
						0
					WHEN EXISTS
						(
							SELECT
									1
							FROM
									SCore.ExpandedObjectSecurityForUser(@ObjectGuid, @UserId) os1
							WHERE
									os1.CanRead > 0
						) THEN
						1
					ELSE
					(CASE
							WHEN ISNULL(os2.HasSecurity, 0) = 0 THEN
								1
							ELSE
							0
					END
					)
			END AS BIT) AS CanRead,
			CAST(CASE
					WHEN EXISTS
						(
							SELECT
									1
							FROM
									SCore.ExpandedObjectSecurityForUser(@ObjectGuid, @UserId) os1
							WHERE
									os1.DenyWrite > 0
						) THEN
						0
					WHEN EXISTS
						(
							SELECT
									1
							FROM
									SCore.ExpandedObjectSecurityForUser(@ObjectGuid, @UserId) os1
							WHERE
									os1.CanWrite > 0
						) THEN
						1
					ELSE
					(CASE
							WHEN ISNULL(os2.HasSecurity, 0) = 0 THEN
								1
							ELSE
							0
					END
					)
			END AS BIT) AS CanWrite
	FROM
			[SCore].[Identities] i
	OUTER APPLY
			(
				SELECT
						1 HasSecurity
				WHERE
						(EXISTS
						(
							SELECT
									1
							FROM
									SCore.ObjectSecurity os3
							WHERE
									(os3.ObjectGuid = @ObjectGuid)
									AND (os3.RowStatus NOT IN (0, 254))
						)
						)
			) AS os2
	WHERE
			(i.ID = @UserId)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SCore].[tvf_OrganisationalUnitsGet]
--
GO
CREATE OR ALTER FUNCTION [SCore].[tvf_OrganisationalUnitsGet]
	(
		@UserId INT
	)
RETURNS TABLE
               --WITH SCHEMABINDING
AS
RETURN SELECT		ou.RowStatus,
					ou.RowVersion,
					ou.Guid,
					ou.Name,
					ou.ID,
					ou2.Guid AS ParentOrganisationalUnitGuid
	   FROM			SCore.OrganisationalUnits ou
	   JOIN			SCore.OrganisationalUnits ou2 ON(ou.ParentID = ou2.ID)
	   OUTER APPLY	SCore.ObjectSecurityForUser(ou.Guid, @UserId) os
	   WHERE		(ou.RowStatus NOT IN (0, 254));
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SCore].[tvf_Identities]
--
GO
CREATE OR ALTER FUNCTION [SCore].[tvf_Identities]
	(
		@UserId INT
	)
RETURNS TABLE
            --WITH SCHEMABINDING
AS
RETURN SELECT		i.ID,
				i.RowStatus,
				i.RowVersion,
				i.Guid,
				i.FullName,
				i.EmailAddress,
				ou.Name AS OrganisationalUnit,
				os.CanWrite
	   FROM			SCore.Identities			  AS i
	   JOIN		Score.OrganisationalUnits ou ON (ou.ID = i.OriganisationalUnitId)
	   OUTER APPLY	SCore.ObjectSecurityForUser (	i.Guid,
													@UserId
												) AS os
	   WHERE		(i.RowStatus NOT IN (0, 254))
			AND	(os.CanRead = 1)
			AND	(i.ID > -1);
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SCore].[tvf_LanguageLabelTranslations]
--
GO
CREATE OR ALTER FUNCTION [SCore].[tvf_LanguageLabelTranslations] 
(
    @UserId INT,
    @ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
               --WITH SCHEMABINDING
AS
RETURN 
SELECT  llt.ID,
        llt.RowStatus, 
        llt.RowVersion,
        llt.Guid,
		llt.Text,
        ll.Name AS LanguageLabel,
		l.Name AS Language
FROM    SCore.LanguageLabelTranslations llt
JOIN	SCore.LanguageLabels ll ON (ll.ID = llt.LanguageLabelID)
JOIN	SCore.Languages l ON (l.ID = llt.LanguageID)
OUTER APPLY SCore.ObjectSecurityForUser(llt.Guid, @UserId) os
WHERE   (llt.RowStatus  NOT IN (0, 254))
    AND (ll.Guid = @ParentGuid)
    AND (os.CanRead = 1)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SCore].[ObjectSecurityForUser_CanWritev]
--
GO
CREATE OR ALTER VIEW [SCore].[ObjectSecurityForUser_CanWritev]
        --WITH SCHEMABINDING
AS
	SELECT	do.Guid,
			i.ID
	FROM	SCore.DataObjects do
	CROSS JOIN	SCore.Identities i
	WHERE	(NOT EXISTS
				(
					SELECT	1
					FROM	SCore.ObjectSecurity os1
					WHERE	(os1.UserId = i.ID)
						AND	(os1.ObjectGuid = do.Guid)
						AND	(os1.DenyWrite > 0)
						AND	(os1.RowStatus NOT IN (0, 254))
				)
			)
		AND	(NOT EXISTS
				(
					SELECT	1
					FROM	SCore.ObjectSecurity os1
					JOIN	SCore.UserGroups ug ON (os1.GroupId = ug.GroupID)
					WHERE	(ug.IdentityID = i.ID)
						AND	(os1.ObjectGuid = do.Guid)
						AND	(os1.DenyWrite > 0)
						AND	(os1.RowStatus NOT IN (0, 254))
				)
			)
		AND	(
				( EXISTS
					(
						SELECT	1
						FROM	SCore.ObjectSecurity os1
						WHERE	(os1.UserId = i.ID)
							AND	(os1.ObjectGuid = do.Guid)
							AND	(os1.CanWrite > 0)
							AND	(os1.RowStatus NOT IN (0, 254))
					)
				)
			OR	( EXISTS
					(
						SELECT	1
						FROM	SCore.ObjectSecurity os1
						JOIN	SCore.UserGroups ug ON (os1.GroupId = ug.GroupID)
						WHERE	(ug.IdentityID = i.ID)
							AND	(os1.ObjectGuid = do.Guid)
							AND	(os1.CanWrite > 0)
							AND	(os1.RowStatus NOT IN (0, 254))
					)
				)
			OR	(NOT EXISTS
					(
						SELECT	1
						FROM	SCore.ObjectSecurity hos3
						WHERE	(hos3.ObjectGuid = do.Guid)
							AND (hos3.RowStatus NOT IN (0, 254))
					)
				)
			)
	 
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SCore].[DirectoryObjectSecurity]
--
GO
CREATE OR ALTER VIEW [SCore].[DirectoryObjectSecurity]
               --WITH SCHEMABINDING
AS
SELECT	os.ObjectGuid, 
		COALESCE(i.EmailAddress, g.DirectoryId, N'') AS DirectoryId,
		CASE	WHEN os.CanWrite = 1 THEN N'write'
				WHEN os.CanWrite = 0 AND os.CanRead = 1 THEN N'read'
				ELSE N''
		END AS [role]
FROM	SCore.ObjectSecurity os 
LEFT JOIN	SCore.Identities i ON (i.ID = os.UserId)
LEFT JOIN	SCore.Groups g ON (g.ID = os.GroupId)
WHERE	(os.RowStatus = 1)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

