CREATE OR ALTER FUNCTION [SJob].[tvf_ContactQuotes] 
(
    @UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
             --WITH SCHEMABINDING
AS
RETURN 
SELECT  q.ID,
        q.RowStatus,
        q.RowVersion,
        q.Guid,
        q.Number,
		q.Date,
		LEFT(q.Overview, 200) AS Overview,
		i.Guid QuotingUserGuid,
		i.FullName AS QuotingUserName
FROM    SSop.Quotes q
JOIN	SCrm.Contacts c ON (c.ID = q.ClientContactId)
JOIN    SCore.Identities i ON (q.QuotingUserId = i.ID)
WHERE   (q.RowStatus  NOT IN (0, 254))
	AND	(q.Id > 0)
	AND	(c.Guid = @ParentGuid)
	AND	(EXISTS
			(				
	SELECT
			1
	FROM
			SCore.ObjectSecurityForUser_CanRead(q.Guid, @UserId) oscr
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[QuoteReopen]
--
GO
CREATE OR ALTER PROCEDURE [SSop].[QuoteReopen]
  @Guid                    UNIQUEIDENTIFIER OUT
AS
  BEGIN
    DECLARE @UserID             INT = -1;

    SELECT
            @UserID = ISNULL(CONVERT(INT,
            SESSION_CONTEXT(N'user_id')
            ),
            -1
            );

    IF (NOT EXISTS
			(
				SELECT	1
				FROM	SCore.UserGroups AS ug
				JOIN	SCore.Groups AS g ON (g.ID = ug.GroupID)
				WHERE	(ug.IdentityID = @UserID)
					AND	(g.Code = N'QUOTESU')
			)
		)
	BEGIN 
		;THROW 60000, N'Only members of the Quote Superusers group can run this action.', 1
	END
	ELSE
	BEGIN 
		UPDATE	q
		SET		q.DeadDate = NULL,
				q.DateRejected = NULL
		FROM	SSop.Quotes AS q
		WHERE	(q.Guid = @Guid)
			AND	(
					(q.DeadDate IS NOT NULL)
				OR	(q.DateRejected IS NOT NULL)
				)

	END
  END;

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

