		SCore.Identities qc ON (qc.ID = q.QuotingConsultantId)
WHERE
		(q.RowStatus NOT IN (0, 254))
		AND (q.ID > 0)
		AND (a.Guid = @ParentGuid)
		AND (EXISTS
		(
			SELECT
					1
			FROM
