--
-- Create or alter function [SJob].[tvf_Jobs_TeamF10ExpiryList]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_TeamF10ExpiryList]
	(
		@UserId INT
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN SELECT	j.ID,
				j.RowStatus,
				j.RowVersion,
				j.Guid,
				j.Number,
				j.JobDescription,
				j.JobTypeID,
				client.Name AS Client,
				jt.Name		AS JobTypeName,
				i.Guid		AS SurveyorGuid,
				i.FullName	AS SurveyorName,
				F10.SubmissionExpiryDate,
				js.IsSubjectToNDA,
				p.FormattedAddressComma, --NEW
				F10.StartDateTimeUTC, --NEW
				F10.DueDateTimeUTC, --NEW
				F10.Reference, --NEW
				js.JobStatus -- NEW
	   FROM		SJob.Jobs		 AS j
	   JOIN		SJob.JobStatus AS js ON (js.ID = j.ID)
	   JOIN		SJob.JobTypes	 AS jt ON (j.JobTypeID = jt.ID)
	   JOIN		SCore.Identities AS i ON (j.SurveyorID = i.ID)
	   JOIN		SCrm.Accounts	 AS client ON (client.ID = j.ClientAccountID)
	   JOIN		SJob.Assets				  AS p ON (p.ID = j.UprnID) -- NEW
	   CROSS APPLY
				(
					SELECT	ou1.OrgNode
					FROM	SCore.OrganisationalUnits AS ou1
					JOIN	SCore.Identities		  AS i1 ON (i1.OriganisationalUnitId = ou1.ID)
					WHERE	(i1.ID = @UserId)
				)					AS CurrentUser
	   CROSS APPLY
				(
					SELECT	
							m.SubmissionExpiryDate, 
							m.StartDateTimeUTC,
							m.DueDateTimeUTC,
							m.Reference 
					FROM	SJob.Milestones		AS m
					JOIN	SJob.MilestoneTypes AS mt ON (mt.ID = m.MilestoneTypeID)
					WHERE	(m.JobID	  = j.ID)
						AND (mt.Code	  = N'F10')
						AND (m.IsComplete = 0)
						AND (m.SubmittedDateTimeUTC IS NOT NULL)
						AND (ISNULL (	m.SubmissionExpiryDate,
										DATEADD (	DAY,
													7,
													GETUTCDATE ()
												)
									)	  < DATEADD (	DAY,
														7,
														GETUTCDATE ()
													)
							)
						AND (m.RowStatus NOT IN (0, 254))
						AND	(NOT EXISTS
								(
									SELECT	1
									FROM	SJob.Milestones AS m1
									WHERE	(m1.RowStatus NOT IN (0, 254))
										AND	(m1.JobID = j.ID)
										AND	(m1.MilestoneTypeID = m.MilestoneTypeID)
										AND (m1.SubmittedDateTimeUTC IS NOT NULL)
										AND	(m1.SubmissionExpiryDate < m.SubmissionExpiryDate)
								)
							)
				)				 AS F10
	   WHERE	(j.RowStatus NOT IN (0, 254))
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
																@UserId
															) AS oscr
		   )
				)
			AND (j.IsActive		   = 1)
			AND (j.IsCompleteForReview = 0)
			AND (j.ReviewedByUserID	   < 0)
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.OrganisationalUnits AS ou2
			   WHERE	(ou2.ID											  = i.OriganisationalUnitId)
					AND (ou2.OrgNode.IsDescendantOf (CurrentUser.OrgNode) = 1)
		   )
					)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_TeamDRRNeedsReview]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_TeamDRRNeedsReview]
	(
		@UserId INT
	)
RETURNS TABLE
         --WITH SCHEMABINDING
AS
RETURN	SELECT	j.ID,
				j.RowStatus,
				j.RowVersion,
				j.Guid,
				j.Number,
				j.JobDescription,
				j.JobTypeID,
				client.Name AS Client,
				jt.Name		AS JobTypeName,
				i.Guid		AS SurveyorGuid,
				i.FullName	AS SurveyorName,
				DRR.ReviewedDateTimeUTC,
				js.IsSubjectToNDA
	   FROM		SJob.Jobs		 AS j
	   JOIN		SJob.JobStatus AS js ON (js.ID = j.ID)
	   JOIN		SJob.JobTypes	 AS jt ON (j.JobTypeID = jt.ID)
	   JOIN		SCore.Identities AS i ON (j.SurveyorID = i.ID)
	   JOIN		SCrm.Accounts	 AS client ON (client.ID = j.ClientAccountID)
	   CROSS APPLY
				(
					SELECT	m.ReviewedDateTimeUTC
					FROM	SJob.Milestones		AS m
					JOIN	SJob.MilestoneTypes AS mt ON (mt.ID = m.MilestoneTypeID)
					WHERE	(m.JobID				 = j.ID)
						AND (m.RowStatus NOT IN (0, 254))
						AND (m.IsComplete			 = 0)
						AND (mt.Code				 = N'DESIGNHAZ')
						AND (m.CompletedDateTimeUTC IS NULL)
						AND
						  (
							  (m.ReviewedDateTimeUTC IS NULL)
						   OR (m.ReviewedDateTimeUTC < DATEADD (   WEEK,
																   -8,
																   GETDATE ()
															   )
							  )
						  )
						AND (NOT EXISTS
						(
							SELECT	1
							FROM	SJob.Milestones AS m1
							WHERE	(m1.JobID				= j.ID)
								AND (m1.MilestoneTypeID		= m.MilestoneTypeID)
								AND (m1.RowStatus NOT IN (0, 254))
								AND (m1.ReviewedDateTimeUTC < m.ReviewedDateTimeUTC)
						)
							)
				)				 AS DRR
	   CROSS APPLY
					(
						SELECT	ou1.OrgNode
						FROM	SCore.OrganisationalUnits AS ou1
						JOIN	SCore.Identities		  AS i1 ON (i1.OriganisationalUnitId = ou1.ID)
						WHERE	(i1.ID = @UserId)
					) AS CurrentUser
	   WHERE	(j.RowStatus NOT IN (0, 254))
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
																@UserId
															) AS oscr
		   )
				)
			AND (j.IsActive			= 1)
			AND (j.IsPendingCompletion = 0)
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.OrganisationalUnits AS ou2
			   WHERE	(ou2.ID											  = i.OriganisationalUnitId)
					AND (ou2.OrgNode.IsDescendantOf (CurrentUser.OrgNode) = 1)
		   )
					)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

