CREATE OR ALTER FUNCTION [SJob].[tvf_JobMilestones]
	(
		@UserId INT,
		@ParentGuid UNIQUEIDENTIFIER
	)
RETURNS TABLE
               --WITH SCHEMABINDING
AS
RETURN SELECT		jm.ID,
					jm.RowStatus,
					jm.RowVersion,
					jm.Guid,
					mt.Name,
					jm.Description Description,
					jm.SortOrder,
					jm.ScheduledDateTimeUTC,
					jm.DueDateTimeUTC,
					jm.StartDateTimeUTC,
					jm.CompletedDateTimeUTC,
					CASE
						WHEN (jm.IsNotApplicable = 1) THEN N'Not Applicable'
						WHEN (ISNULL (	 jm.CompletedDateTimeUTC,
										 '1970-01-02'
									 ) > '1970-01-02'
							 ) THEN N'Complete'
						WHEN
						   (
							   ISNULL (	  jm.DueDateTimeUTC,
										  '1970-01-02'
									  ) < GETUTCDATE ()
						   AND	(ISNULL (	jm.DueDateTimeUTC,
											'1970-01-02'
										) > '1970-01-02'
								)
						   ) THEN N'Overdue'
						WHEN (ISNULL (	 jm.StartDateTimeUTC,
										 '1970-01-02'
									 ) > '1970-01-02'
							 ) THEN N'Started'
						WHEN (ISNULL (	 jm.ScheduledDateTimeUTC,
										 '1970-01-02'
									 ) > '1970-01-02'
							 ) THEN N'Scheduled'
						ELSE N'Incomplete'
					END		AS StatusText
	   FROM			SJob.Milestones				  AS jm
	   JOIN			SJob.MilestoneTypes			  AS mt ON (mt.ID = jm.MilestoneTypeID)
	   JOIN			SJob.Jobs					  AS j ON (j.ID = jm.JobID)
	   WHERE		(jm.RowStatus NOT IN (0, 254))
				AND (j.Guid		= @ParentGuid)
				AND	(EXISTS
			(
				SELECT	1
				FROM	SCore.ObjectSecurityForUser_CanRead (jm.guid, @UserId) oscr
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_AllActiveF10]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_AllActiveF10]
	(
		@UserId INT
	)

RETURNS TABLE
    --WITH SCHEMABINDING
AS
RETURN SELECT		j.ID,
					j.RowStatus,
					j.Guid,
					j.RowVersion,
					i.FullName,
					j.Number,
					j.JobDescription,
					p.FormattedAddressComma,
					m.StartDateTimeUTC,
					ISNULL (   m.DueDateTimeUTC,
							   m.ScheduledDateTimeUTC
						   ) AS NextAction,
					m.Reference,
					js.JobStatus
	   FROM			SJob.Jobs					  AS j
	   JOIN			SJob.JobStatus				  AS js ON (js.ID = j.ID)
	   JOIN			SCore.Identities			  AS i ON (i.ID = j.SurveyorID)
	   JOIN			SJob.Milestones				  AS m ON (m.JobID = j.ID)
	   JOIN			SJob.MilestoneTypes			  AS mt ON (mt.ID = m.MilestoneTypeID)
	   JOIN			SJob.Assets				  AS p ON (p.ID = j.UprnID)
	   WHERE		(mt.Name = N'F10')
				AND (m.RowStatus NOT IN (0, 254))
				AND (m.StartDateTimeUTC IS NOT NULL)
				AND	(j.IsComplete = 0)
				AND	(EXISTS
			(
					SELECT
							1
					FROM
							SCore.ObjectSecurityForUser_CanRead(j.Guid, @UserId) oscr
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

