--
-- Create or alter function [SFin].[tvf_TransactionAllocations]
--
GO
CREATE OR ALTER FUNCTION [SFin].[tvf_TransactionAllocations] 
(
    @UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
              --WITH SCHEMABINDING
AS
RETURN 
SELECT  ta.ID,
		ta.RowStatus,
		ta.RowVersion,
		ta.Guid,
		st.Number AS SourceTransationNumber,
		st.Date AS SourceTransactionDate,
		tt.Number AS TargetTransactionNumber,
		tt.Date AS TargetTransactionDate,
		ta.AllocatedAmount
FROM    SFin.TransactionAllocations ta 
JOIN	SFin.Transactions st ON (st.ID = ta.SourceTransactionID)
JOIN	SFin.Transactions tt ON (tt.ID = ta.TargetTransactionID)
WHERE   (ta.RowStatus  NOT IN (0, 254))
	AND	(ta.Id > 0)
	AND	((st.Guid = @ParentGuid) OR (tt.Guid = @ParentGuid))
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SFin].[tvf_SageExports]
--
GO



CREATE OR ALTER FUNCTION [SFin].[tvf_SageExports] 
(
    @UserId INT
)
RETURNS TABLE
     --WITH SCHEMABINDING
AS
RETURN 
SELECT  se.ID,
        se.RowStatus,
        se.RowVersion,
        se.Guid,
		se.InclusiveToDate,
        ou.Name AS OrganisationalUnit,
		COUNT(setr.ID) AS IncludedTransactions
FROM    SFin.SageExports se
LEFT JOIN	SFin.SageExportTransactions AS setr ON (setr.SageExportID = se.ID)
JOIN	SCore.OrganisationalUnits AS ou ON (ou.ID = se.OrganisationalUnitId)
WHERE   (se.RowStatus  NOT IN (0, 254))
	AND	(se.Id > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(se.Guid, @UserId) oscr
			)
		)
		AND	((EXISTS
			(				
	SELECT
			1
	FROM
			SCore.ObjectSecurityForUser_CanRead(ou.Guid, @UserId) oscr
			)
		) OR ou.ID < 0)
	GROUP BY se.ID, se.RowStatus, SE.RowVersion, se.Guid, se.InclusiveToDate, ou.Name
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

