						AND (m.RowStatus NOT IN (0, 254))
						AND (mt.Code	  = N'PCI')
						AND (m.IsComplete = 1)
						AND (NOT EXISTS
						(
							SELECT	1
							FROM	SJob.Milestones AS m1
							WHERE	(m1.JobID				 = j.ID)
								AND (m1.MilestoneTypeID		 = m.MilestoneTypeID)
								AND (m1.RowStatus NOT IN (0, 254))
