    JOIN
        [SCore].[EntityHobts]      h
            ON (ep.EntityHoBTID = h.id)
    JOIN
        SCore.EntityTypes      et
            ON (et.ID = h.EntityTypeId)
    JOIN
        SCore.EntityDataTypes edt 
            ON (edt.ID = ep.EntityDataTypeID)
    JOIN
        SCore.EntityPropertyGroups epg 
            ON (epg.ID = ep.EntityPropertyGroupID)
