--
-- Create or alter function [SUserInterface].[tvf_GridViewColumnDefinitions]
--
GO
CREATE OR ALTER FUNCTION [SUserInterface].[tvf_GridViewColumnDefinitions]
  (
    @GridViewDefinitionId INT,
    @UserId       INT
  )
RETURNS TABLE
   --WITH SCHEMABINDING
AS
  RETURN SELECT
          gvcd.ID,
          gvcd.RowStatus,
          gvcd.RowVersion,
          gvcd.Guid,
          gvcd.Name,
          gvcd.ColumnOrder,
          olfu.Label AS Title,
          gvcd.GridViewDefinitionId,
          gvcd.IsPrimaryKey,
          gvcd.IsHidden,
          gvcd.IsFiltered,
          gvcd.IsCombo,
          gvcd.IsLongitude,
          gvcd.IsLatitude,
          gvcd.DisplayFormat,
          gvcd.Width,
