--
-- Create or alter function [SSop].[tvf_Quotes_CreatedJobs]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_Quotes_CreatedJobs] 
(
	@ParentGuid UNIQUEIDENTIFIER,
    @UserId INT
)
RETURNS TABLE
             --WITH SCHEMABINDING
AS
RETURN 
SELECT  j.ID,
        j.RowStatus,
        j.RowVersion,
        j.Guid,
        j.Number,
        j.JobDescription,
        j.JobTypeID,
        jt.Name AS JobTypeName,
		i.Guid SurveyorGuid,
		i.FullName AS SurveyorName, 
		j.IsComplete,
		js.JobStatus
FROM    SJob.Jobs j
JOIN	SJob.JobStatus js ON (js.ID = j.ID)
JOIN    SJob.JobTypes jt ON (j.JobTypeID = jt.ID)
JOIN    SCore.Identities i ON (j.SurveyorID = i.ID)
WHERE   (j.RowStatus  NOT IN (0, 254))
	AND	(j.Id > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(j.Guid, @UserId) oscr
			)
		)
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.QuoteItems qi
				JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
				WHERE	(q.Guid = @ParentGuid)
					AND	(qi.CreatedJobId = j.ID) 
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_EnquiryCreatedJobs]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiryCreatedJobs]
(
	@UserID INT,
	@EnquiryGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
	-- --WITH SCHEMABINDING
AS
RETURN 
SELECT	j.ID, 
		j.Guid, 
		j.RowStatus,
		j.RowVersion,
		j.Number,
		j.ExternalReference,
		js.JobStatus
FROM	SJob.Jobs AS j
JOIN	SJob.JobStatus AS js ON (js.ID = j.ID)
WHERE	(j.RowStatus NOT IN (0, 254))
	AND	(j.ID > 0)
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.Enquiries AS e
				JOIN	SSop.EnquiryServices es ON (es.EnquiryId = e.ID)
				JOIN	SSop.Quotes q ON (q.EnquiryServiceID = es.ID)
				JOIN	SSop.QuoteItems qi ON (qi.QuoteId = q.ID)
				WHERE	(qi.CreatedJobId = j.ID)
					AND	(e.Guid = @EnquiryGuid)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[QuotesRevise]
--
GO
CREATE OR ALTER PROCEDURE [SSop].[QuotesRevise] @SourceGuid UNIQUEIDENTIFIER,
								  @TargetGuid UNIQUEIDENTIFIER
AS
BEGIN

	DECLARE @SourceID INT,
			@ID		  INT,
			@IsInsert BIT;

	SELECT	@SourceID = ID
	FROM	SSop.Quotes
	WHERE	(Guid = @SourceGuid);

	IF (@@ROWCOUNT > 1)
	BEGIN
		;
		THROW 60000, N'Invalid source Quote', 1;
	END;

	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes AS q
		 WHERE	(q.Guid = @SourceGuid)
			AND (q.DateAccepted IS NOT NULL)
	 )
	   )
	BEGIN
		; THROW 60000, N'You cannot revise an accepted quote', 1;
	END;

	EXEC SCore.UpsertDataObject @Guid = @TargetGuid,
								@SchemeName = N'SSop',
								@ObjectName = N'Quotes',
								@IncludeDefaultSecurity = 1,
								@IsInsert = @IsInsert;

	INSERT	SSop.Quotes
		 (RowStatus,
		  Guid,
		  OrganisationalUnitID,
		  QuotingUserId,
		  Number,
		  UprnId,
		  ClientAccountId,
		  ClientAddressId,
		  ClientContactId,
		  ContractID,
		  Date,
		  Overview,
		  ExpiryDate,
		  QuoteSourceId,
		  IsSubjectToNDA,
		  AgentAccountId,
		  AgentAddressId,
		  AgentContactId,
		  ExternalReference,
		  FeeCap,
		  RevisionNumber,
		  OriginalQuoteId,
		  EnquiryServiceID,
		  DescriptionOfWorks,
		  QuotingConsultantId,
		  ExclusionsAndLimitations,
		  ProjectId,
		  AgentContractID)
	SELECT	0,
			@TargetGuid,
			q.OrganisationalUnitID,
			q.QuotingUserId,
			q.Number,
			q.UprnId,
			q.ClientAccountId,
			q.ClientAddressId,
			q.ClientContactId,
			q.ContractID,
			GETDATE (),
			q.Overview,
			DATEADD (	MONTH,
						6,
						GETDATE ()
					),
			q.QuoteSourceId,
			q.IsSubjectToNDA,
			q.AgentAccountId,
			q.AgentAddressId,
			q.AgentContactId,
			q.ExternalReference,
			q.FeeCap,
			ISNULL (   latest_revision.rev,
					   0
				   ) + 1,
			CASE
				WHEN q.OriginalQuoteId = (-1) THEN q.ID
				ELSE q.OriginalQuoteId
			END,
			q.EnquiryServiceID,
			q.DescriptionOfWorks,
			q.QuotingConsultantId,
			q.ExclusionsAndLimitations,
			q.ProjectId,
			q.AgentContractID
	FROM	SSop.Quotes AS q
	OUTER APPLY
			(
				SELECT	MAX (q1.RevisionNumber) AS rev
				FROM	SSop.Quotes AS q1
				WHERE	(q1.OriginalQuoteId = CASE
												  WHEN q.OriginalQuoteId = (-1) THEN q.ID
												  ELSE q.OriginalQuoteId
											  END
						)
			)			AS latest_revision
	WHERE	(q.ID = @SourceID);

	SELECT	@ID = SCOPE_IDENTITY ();


	-- Build the collection of items to duplicate. 
	DECLARE @QuoteItems SCore.TwoGuidUniqueList;

	INSERT	@QuoteItems
		 (GuidValue, GuidValueTwo)
	SELECT	qi.Guid,
			NEWID ()
	FROM	SSop.QuoteItems AS qi
	WHERE	(qi.QuoteId = @SourceID)
		AND (qi.RowStatus NOT IN (0, 254));

	-- Build the collection of payment stages to duplicate
	DECLARE @QuotePaymentStages SCore.TwoGuidUniqueList;

	INSERT	@QuotePaymentStages
		 (GuidValue, GuidValueTwo)
	SELECT	qps.Guid,
			NEWID ()
	FROM	SSop.QuotePaymentStages AS qps
	WHERE	(qps.QuoteId = @SourceID)
		AND (qps.RowStatus NOT IN (0, 254));

	-- Build the collection of quote memos
	DECLARE @QuoteMemos SCore.TwoGuidUniqueList;

	INSERT	@QuoteMemos --RETURNS NOTHING
		 (GuidValue, GuidValueTwo)
	SELECT	qm.Guid,
			NEWID ()
	FROM	SSop.QuoteMemos AS qm
	WHERE	(qm.QuoteID = @SourceID)
		AND (qm.RowStatus NOT IN (0, 254));

	-- Create the data objects. 
	DECLARE @NewGuidList SCore.GuidUniqueList;

	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	GuidValueTwo
	FROM	@QuoteItems;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,		-- GuidUniqueList
									@SchemeName = N'SSop',			-- nvarchar(255)
									@ObjectName = N'QuoteItems',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;	-- bit	

	DELETE	FROM @NewGuidList;
	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	GuidValueTwo
	FROM	@QuotePaymentStages;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,				-- GuidUniqueList
									@SchemeName = N'SSop',					-- nvarchar(255)
									@ObjectName = N'QuotePaymentStages',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;			-- bit	

	DELETE	FROM @NewGuidList;
	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	qm.GuidValueTwo
	FROM	@QuoteMemos AS qm;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,		-- GuidUniqueList
									@SchemeName = N'SSop',			-- nvarchar(255)
									@ObjectName = N'QuoteMemos',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;	-- bit	

	-- Duplicate the Quote Items. 
	INSERT	SSop.QuoteItems
		 (RowStatus, Guid, QuoteId, ProductId, Details, Net, VatRate, DoNotConsolidateJob, SortOrder, Quantity)
	SELECT	1,
			qil.GuidValueTwo,
			@ID,
			qi.ProductId,
			qi.Details,
			qi.Net,
			qi.VatRate,
			qi.DoNotConsolidateJob,
			qi.SortOrder,
			qi.Quantity
	FROM	SSop.QuoteItems	   AS qi
	JOIN	@QuoteItems		   AS qil ON (qil.GuidValue = qi.Guid)
	JOIN	SSop.QuoteSections AS oqs ON (oqs.ID		= qi.QuoteSectionId);


	-- Duplicate the Quote Payment Stages 
	INSERT INTO SSop.QuotePaymentStages
		 (RowStatus, Guid, QuoteId, PaymentFrequencyTypeId, PaymentFrequency, Value, PercentageOfTotal, PayAfterStageId)
	SELECT	1,
			qpsl.GuidValueTwo,
			@ID,
			qps.PaymentFrequencyTypeId,
			qps.PaymentFrequency,
			qps.Value,
			qps.PercentageOfTotal,
			qps.PayAfterStageId
	FROM	SSop.QuotePaymentStages AS qps
	JOIN	@QuotePaymentStages		AS qpsl ON (qps.Guid = qpsl.GuidValue);

	-- Duplicate the Quote Memos
	INSERT INTO SSop.QuoteMemos
		 (RowStatus, Guid, QuoteID, Memo, CreatedDateTimeUTC, CreatedByUserId)
	SELECT	1,
			qms.GuidValueTwo,
			@ID,
			qm.Memo,
			qm.CreatedDateTimeUTC,
			qm.CreatedByUserId
	FROM	SSop.QuoteMemos AS qm
	JOIN	@QuoteMemos		AS qms ON (qm.Guid = qms.GuidValue);

	UPDATE	SSop.Quotes
	SET		RowStatus = 1
	WHERE	(ID = @ID);
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Enquiry_CalculatedFields]
--
GO
CREATE OR ALTER VIEW [SSop].[Enquiry_CalculatedFields]
   --WITH SCHEMABINDING
AS
SELECT	e.ID,
		CASE
		WHEN e.DeadDate IS NOT NULL THEN N'Dead'
			WHEN e.DeclinedToQuoteDate IS NOT NULL THEN N'Declined'			
			WHEN e.QuotingDeadlineDate < DATEADD(DAY, 2, GETDATE ()) THEN N'Deadline Approaching'
			WHEN e.QuotingDeadlineDate < GETDATE () THEN N'Deadline Missed'
						WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.QuoteItems AS qi 
											WHERE	(qi.QuoteId = q.ID)
												AND (qi.RowStatus NOT IN (0,254))
												AND	(qi.CreatedJobId < 0)
										)
									)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = e.ID)
												AND	(q2.DateAccepted IS NULL)
												AND	(q2.DeadDate IS NULL)
												AND	(q2.DateRejected IS NULL)
										)
									)
					   )
				 ) THEN N'Complete'
			WHEN (EXISTS
						(
						    SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   JOIN     SSop.QuoteItems AS qi ON (qi.QuoteId = q.ID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(qi.CreatedJobId > 0)
									AND	( EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = e.ID)
												AND	(q2.DateAccepted IS NULL)
												AND	(q2.DeadDate IS NULL)
												AND	(q2.DateRejected IS NULL)
												AND (es2.RowStatus NOT IN (0,254))
										)
									)
									AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.QuoteItems AS qi 
											WHERE	(qi.QuoteId = q.ID)
												AND	(qi.CreatedJobId < 0)
										)
									)
								
						)
				) THEN N'Part Complete'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND	(q2.DateAccepted IS NULL) 
												AND	(q2.DateRejected IS NULL)
												AND	(q2.DeadDate IS NULL)
												AND (q2.ExpiryDate > GETDATE())
												
										)
									)
					   )
				 ) THEN N'Accepted'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND (q2.ExpiryDate > GETDATE())
												AND	(q2.DateAccepted IS NULL) -- Was using q.DateAccepted
												AND (q2.DateRejected IS NULL) --Exclude rejected
												AND (q2.DeadDate IS NULL) --Exclude where dead date is set.
												
										)
									)
					   )
				 ) THEN N'Part Accepted'

			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateRejected IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND	(q.DateRejected IS NULL) 
										)
									)

					   )
				 ) THEN N'Rejected'


			WHEN (EXISTS
						(
							SELECT 1
							FROM SSop.Quotes AS q
							JOIN SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
							WHERE	(es.EnquiryId		 = e.ID)
								AND (q.ExpiryDate < GETDATE())
								AND (EXISTS
										(
											SELECT 1
											FROM SSop.Quotes AS q2
											JOIN SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE (q2.ID <> q.ID)
												AND (q2.ExpiryDate < GETDATE())
										)
									)
						)
				 ) THEN N'Expired'
			WHEN (EXISTS
				   (
					   SELECT 1
					   FROM SSop.EnquiryServices es
					   WHERE es.EnquiryId = e.ID
					   AND es.RowStatus NOT IN (0,254) -- Ensure active enquiry services
					   HAVING COUNT(es.ID) > 1 -- Ensure multiple services
				   )
				   AND (EXISTS
					   (
						   SELECT 1
						   FROM SSop.Quotes q
						   JOIN SSop.EnquiryServices es ON q.EnquiryServiceID = es.ID
						   WHERE es.EnquiryId = e.ID
						   AND es.RowStatus NOT IN (0,254)
						   AND q.DateSent IS NOT NULL
					   )
				   )
				   AND (EXISTS
					   (
						   SELECT 1
						   FROM SSop.Quotes q2
						   JOIN SSop.EnquiryServices es2 ON q2.EnquiryServiceID = es2.ID
						   WHERE es2.EnquiryId = e.ID
						   AND es2.RowStatus NOT IN (0,254)
						   AND q2.DateSent IS NULL
						   AND q2.DateRejected IS NULL
						   AND q2.DateDeclinedToQuote IS NULL
					   )
				   )
			) THEN N'Part Sent'
					WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateSent IS NOT NULL)
					   )
				 ) THEN N'Sent'
				
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								
								
					   )
				 ) THEN N'Quoting'
			WHEN e.IsReadyForQuoteReview = 1 THEN N'Ready for Quote'
			WHEN e.ChaseDate1 IS NOT NULL AND e.ChaseDate2 IS NULL THEN N'1st Chase'
			WHEN e.ChaseDate2 IS NOT NULL THEN N'2nd Chase'
			
			ELSE N'New'
		END AS EnquiryStatus
FROM	SSop.Enquiries AS e
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_Enquiries]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_Enquiries]
(
	@UserId INT
)
RETURNS TABLE
     --WITH SCHEMABINDING
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		CASE WHEN e.Revision = 0 THEN e.Number ELSE (e.Number + N' (' + CONVERT(NVARCHAR(2), e.Revision) + N') ') END AS Number,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		uprn.AssetNumber AS UPRN,
		ecf.EnquiryStatus,
		ISNULL(p.IsSubjectToNDA, e.IsSubjectToNDA) AS IsSubjectToNDA,
		CASE WHEN ServiceTypes.Name IS NULL THEN N'Multi Discipline' ELSE ServiceTypes.Name END AS Disciplines,
		org.Name AS OrgUnit,
		e.Date 
FROM    SSop.Enquiries e
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
JOIN	SSop.Projects AS p ON (p.ID = e.ProjectId)
JOIN	SCore.OrganisationalUnits AS org ON (org.ID = e.OrganisationalUnitID)
OUTER APPLY (
	SELECT	jt.Name
	FROM	SJob.JobTypes AS jt
	WHERE	(EXISTS
				(
					SELECT	1
					FROM 	SSop.EnquiryServices AS es 
					WHERE	(es.JobTypeId = jt.ID)
						AND	(es.EnquiryId = e.ID)
						AND	(es.RowStatus NOT IN (0, 254))
						AND	(NOT EXISTS
								(
									SELECT	1
									FROM	SSop.EnquiryServices es2 
									WHERE	(es2.ID <> es.ID)
										AND	(es2.EnquiryId = es.EnquiryId)
										AND	(es2.RowStatus NOT IN (0, 254))
								)
							)
				)
			)
) AS ServiceTypes
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_OpenEnquiries]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_OpenEnquiries]
(
	@UserId INT
)
RETURNS TABLE
     --WITH SCHEMABINDING
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		CASE WHEN e.Revision = 0 THEN e.Number ELSE (e.Number + N' (' + CONVERT(NVARCHAR(2), e.Revision) + N') ') END AS Number,
		e.QuotingDeadlineDate,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		ecf.EnquiryStatus
FROM    SSop.Enquiries e
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)
	AND	(e.DeclinedToQuoteDate IS NULL)
	AND	(EXISTS
			(
				SELECT	1
				FROM	SSop.EnquiryServices es 
				WHERE	(es.EnquiryId = e.ID)
					AND	(es.RowStatus NOT IN (0, 254))
					AND	(es.QuoteId < 0)
			)
		)
	AND	(e.Date > DATEADD(MONTH, -6, GETDATE()))
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_EnquiriesForQuoteReview]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiriesForQuoteReview]
(
	@UserId INT
)
RETURNS TABLE
            --WITH SCHEMABINDING
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		e.Number,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN acc.Name <> N'' THEN acc.Name ELSE e.ClientName END AS Account,
		-- New fields
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		ecf.EnquiryStatus
FROM    SSop.Enquiries e
JOIN	SCrm.Accounts acc ON (acc.ID = e.ClientAccountID)
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)
	AND	(e.IsReadyForQuoteReview = 1)
	AND	(EXISTS
			(
				SELECT	1
				FROM	SSop.EnquiryServices es
				WHERE	(es.EnquiryId = e.ID)
					AND	(es.RowStatus NOT IN (0, 254))
					AND	(NOT EXISTS
							(
								SELECT	1
								FROM	SSop.Quotes AS q
								WHERE	(q.EnquiryServiceID = es.ID)
									AND	(q.RowStatus NOT IN (0, 254))
							)
						)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[QuoteItemTotals]
--
GO
CREATE OR ALTER VIEW [SSop].[QuoteItemTotals]
             --WITH SCHEMABINDING
AS 
SELECT	qi.ID,
		CONVERT(DECIMAL(19, 2), ROUND((qi.Net * (qi.VatRate / 100)), 2)) AS Vat,
		CONVERT(DECIMAL(19, 2), ROUND(qi.Net + ROUND((qi.net * ((qi.VatRate / 100))), 2), 2)) AS Gross,
		CONVERT(DECIMAL(19, 2), ROUND ((qi.net * qi.Quantity), 2)) AS LineNet,
		CONVERT(DECIMAL(19, 2), ROUND((ROUND ((qi.net * qi.Quantity), 2) * (qi.VatRate / 100 )), 2)) AS LineVat,
		CONVERT(DECIMAL(19, 2), ROUND(ROUND ((qi.net * qi.Quantity), 2) + ROUND((ROUND ((qi.net * qi.Quantity), 2) * ((qi.VatRate / 100 ))), 2), 2)) AS LineGross
FROM	SSop.QuoteItems qi
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuoteFeeDrawdown]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteFeeDrawdown] 
(
    @UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
       --WITH SCHEMABINDING
AS
RETURN 
SELECT		q.ID,
			q.RowStatus,
			q.Guid,
			CASE
				WHEN rs.Number = 0 THEN N'Fee Cap'
				WHEN rs.Number = 99 THEN N'Pre-Construction'
				WHEN rs.Number = 999 THEN N'Construction'
				ELSE CONVERT (	 NVARCHAR(10),
								 rs.Number
							 )
			END AS Stage,
			ISNULL(CASE rs.Number
				WHEN 0 THEN q.FeeCap
				ELSE stages.Net
			END, 0) AS Quoted
FROM		SSop.Quotes		AS q
CROSS JOIN	SJob.RibaStages AS rs
OUTER APPLY
			(
				SELECT		CASE WHEN qi.ProvideAtStageID = -1 THEN 2 ELSE qi.ProvideAtStageID END  AS RibaStage,
							SUM(qit.LineNet) AS Net
				FROM		SSop.QuoteItems		AS qi
				JOIN		SSop.QuoteItemTotals AS qit ON (qi.ID = qit.ID)
				WHERE		(qi.QuoteId = q.ID)
						AND (qi.RowStatus NOT IN (0, 254))
						AND	(CASE WHEN qi.ProvideAtStageID = -1 THEN 2 ELSE qi.ProvideAtStageID END = rs.ID)
				GROUP BY	CASE WHEN qi.ProvideAtStageID = -1 THEN 2 ELSE qi.ProvideAtStageID END
			)				AS stages
WHERE		(rs.ID	> 0)
		AND (q.Guid = @ParentGuid)
		AND	(
				(
						(rs.IsRealStage = 1)
						AND	(NOT EXISTS
								(
									SELECT	1
									FROM	SSop.QuoteSections eqs
									JOIN	SJob.RibaStages ers ON (ers.ID = eqs.RibaStageId)
									WHERE	(eqs.QuoteId = q.ID)
										AND	(eqs.RowStatus NOT IN (0, 254))
										AND	(ers.Number IN (99, 999))
								)
							)
					)
				OR	(
						(rs.IsRealStage = 0)
						AND	(EXISTS
								(
									SELECT	1
									FROM	SSop.QuoteSections eqs
									JOIN	SJob.RibaStages ers ON (ers.ID = eqs.RibaStageId)
									WHERE	(eqs.QuoteId = q.ID)
										AND	(eqs.RowStatus NOT IN (0, 254))
										AND	(ers.Number IN (99, 999))
								)
							)
					)
			)
UNION ALL
SELECT	q.Id,
		q.RowStatus,
		q.Guid,
		N'Total (ex. Fee Cap.)',
		sections.Total AS Quoted
FROM	SSop.Quotes q
OUTER APPLY (
	SELECT SUM(qit.LineNet) AS Total
	FROM	SSop.QuoteItems  qi
	JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
	WHERE	(qi.QuoteId = q.ID)
) AS sections
WHERE	(q.Guid = @ParentGuid)
UNION ALL
SELECT	q.Id,
		q.RowStatus,
		q.Guid,
		N'Total (inc. Fee Cap.)',
		sections.Total + q.FeeCap AS Quoted
FROM	SSop.Quotes q
OUTER APPLY (
	SELECT SUM(qit.LineNet) AS Total
	FROM	SSop.QuoteItems  qi
	JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
	WHERE	(qi.QuoteId = q.ID)
) AS sections
WHERE	(q.Guid = @ParentGuid)

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

