--
-- Create or alter function [SSop].[tvf_QuotesValidate]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuotesValidate]
	(
		@Guid UNIQUEIDENTIFIER,
		@DateSent DATE,
		@DeadDate DATE,
		@DateRejected DATE,
		@IsFinal BIT,
		@RevisionNumber INT,
		@OrganisationalUnitGuid UNIQUEIDENTIFIER,
		@DateDeclinedToQuote DATE,
		@DeclinedToQuoteReason NVARCHAR(MAX),
		@ContractGuid UNIQUEIDENTIFIER,
		@AgentContractGuid UNIQUEIDENTIFIER
	)
RETURNS @ValidationResult TABLE
	(
		ID INT IDENTITY(1, 1) NOT NULL,
		TargetGuid UNIQUEIDENTIFIER NOT NULL DEFAULT ('00000000-0000-0000-0000-000000000000'),
		TargetType CHAR(1) NOT NULL DEFAULT (''),
		IsReadOnly BIT NOT NULL DEFAULT ((0)),
		IsHidden BIT NOT NULL DEFAULT ((0)),
		IsInvalid BIT NOT NULL DEFAULT ((0)),
		IsInformationOnly BIT NOT NULL DEFAULT ((0)),
		Message NVARCHAR(2000) NOT NULL DEFAULT ('')
	)
AS
BEGIN
	DECLARE @EntityTypeGuid UNIQUEIDENTIFIER = '1c4794c1-f956-4c32-b886-5500ac778a56';

	-- Prevent changing the Quote if the Enquiry is no set as ready for quote review. 
	-- This would be the case if the enquiry had been duplicated. 
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes			 AS q
		 JOIN	SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
		 JOIN	SSop.Enquiries		 AS e ON (e.ID	 = es.EnquiryId)
		 WHERE	(q.Guid					 = @Guid)
			AND (e.IsReadyForQuoteReview = 0)
	 )
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT
				 ep.Guid,
				 N'P',
				 1,
				 0,
				 0,
				 N''
		FROM	SCore.EntityProperties AS ep
		JOIN	SCore.EntityHobts AS eh ON (eh.ID = ep.EntityHoBTID)
		JOIN	SCore.EntityTypes AS et ON (et.ID = eh.EntityTypeID)
		WHERE	(et.Name = N'Quotes')

		RETURN;
	END;


	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.QuoteItems AS qi
		 JOIN	SSop.Quotes		AS q ON (q.ID = qi.QuoteId)
		 WHERE	(q.Guid			 = @Guid)
			AND (qi.RowStatus NOT IN (0, 254))
			AND (qi.CreatedJobId > 0)
	 )
	   )
	OR	(@DeadDate IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityTypeGuid,
				 N'E',
				 1,
				 0,
				 0,
				 N''
			 );

		RETURN;
	END;

	-- Hide fields from CDM based quotes 
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SCore.OrganisationalUnits AS ou
		 WHERE	(ou.Guid = @OrganisationalUnitGuid)
			AND (ou.Name LIKE N'CDM%')
	 )
	   )
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'FeeCap');
	END;

	/*IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.QuoteSections AS qs
		 JOIN	SSop.Quotes		   AS q ON (q.ID = qs.QuoteId)
		 WHERE	(q.Guid			= @Guid)
			AND (qs.RibaStageId < 0)
			AND (qs.RowStatus NOT IN (0, 254))
	 )
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				0,
				1,
				N'All sections must have a Stage set.'
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'Number');
	END;*/

	IF (@RevisionNumber < 1)
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= (N'RevisionNumber'));


	END;

	--[CBLD-592] Check if the DeclinedToQuoteDate is set & there is no reason why it's been declined.
	IF (
		   @DateDeclinedToQuote IS NOT NULL
	   AND	@DeclinedToQuoteReason = N''
	   )
	BEGIN
		DECLARE @EntityPropertyGuid UNIQUEIDENTIFIER;
		SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																	  N'Quotes',
																	  N'DeclinedToQuoteReason'
																  );

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityPropertyGuid,
				 N'P',
				 0,
				 0,
				 1,
				 N'You must enter the reason why we declined to quote.'
			 );
	END;

	----[CBLD-592] Check if the DeclinedToQuoteDate is set - if it is, set IsReadOnly for the whole form.
	IF (
		   @DateDeclinedToQuote IS NOT NULL
	   AND	@DeclinedToQuoteReason <> N''
	   AND	NOT EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes AS q
		 WHERE	q.Guid					= @Guid
			AND q.DeclinedToQuoteReason = N''
	 )
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes');

		RETURN;
	END;

	/* Don't allow the user to progress the status further than Send until the quote has been marked as Sent. */
	IF (@DateSent IS NULL)
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name IN (N'DateAccepted', N'DateRejected', N'RejectionReason', N'ChaseDate1', N'ChaseDate2'));

	END;

	/* Once the quote has been sent you can't unset it as "Is Final" */
	IF (@DateSent IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'IsFinal');
	END;

	/* Don't allow the quote to be sent until it has been set as "Is Final" */
	IF (@IsFinal = 0)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'DateSent');
	END;

	/* Hide Rejection Reason if the Quote hasn't been rejected. */
	IF (@DateRejected IS NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'RejectionReason');
	END;

	--Hide AgentContractID if ContractID is set, and vice-versa.
	IF (@ContractGuid <> '00000000-0000-0000-0000-000000000000')
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= (N'AgentContractID'));
	END
	ELSE IF (@AgentContractGuid <> '00000000-0000-0000-0000-000000000000')
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= (N'ContractID'));
	END;


	IF (@IsFinal = 1)
   AND	(NOT EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes AS q
		 WHERE	(q.Guid						= @Guid)
			AND (q.LegacyId IS NOT NULL)
			AND
				(
					(q.OrganisationalUnitID < 0)
				 OR (q.QuotingUserId		< 0)
				 OR (q.QuotingConsultantId	< 0)
				)
	 )
		)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name NOT IN (N'ChaseDate2', N'ChaseDate1', N'RejectionReason', N'DateRejected', N'DateAccepted',
									N'IsFinal', N'DateSent'
								   )
				);

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quote_ExtendedInfo')
		
				


		IF (ISNULL (
				 (
					 SELECT SUM (qit.LineNet)
					 FROM	SSop.QuoteItemTotals AS qit
					 JOIN	SSop.QuoteItems		 AS qi ON (qi.ID = qit.ID)
					 JOIN	SSop.Quotes			 AS q ON (q.ID	 = qi.QuoteId)
					 WHERE	(q.Guid = @Guid)
						AND (qi.RowStatus NOT IN (0, 254))
				 ),
				 0
				   ) <= 0
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					0,
					1,
					N'A final quote must have a net value greater than 0.'
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	(epfvv.[Schema] = N'SSop')
				AND (epfvv.Hobt		= N'Quotes')
				AND (epfvv.Name		= N'IsFinal');
		END;

	END;



	RETURN;
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[EnquiryServicesExtUpsert]
--
GO
CREATE OR ALTER PROCEDURE [SSop].[EnquiryServicesExtUpsert]
	(	@DateSent DATE,
		@DateAccepted DATE,
		@DateRejected DATE,
		@DateDeclinedToQuote DATE, --[CBLD-592]
		@DateDeclinedToQuoteReason NVARCHAR(MAX),
		@QuoteGuid UNIQUEIDENTIFIER,
		@Guid UNIQUEIDENTIFIER
	)
AS
BEGIN

	IF (@QuoteGuid = '00000000-0000-0000-0000-000000000000')
	BEGIN
		RETURN;
	END;

	--[CBLD-592] -Declined to quote handling.
	IF(@DateDeclinedToQuote IS NOT NULL)
		BEGIN
			UPDATE	SSop.Quotes
			SET		DateDeclinedToQuote = @DateDeclinedToQuote
			WHERE	(Guid = @QuoteGuid);
		END;

	IF(@DateDeclinedToQuoteReason <> N'')
		BEGIN
			UPDATE	SSop.Quotes
			SET		DeclinedToQuoteReason = @DateDeclinedToQuoteReason
			WHERE	(Guid = @QuoteGuid);
		END;

	IF (
		   @DateSent IS NOT NULL
		OR	@DateAccepted IS NOT NULL
		OR	@DateRejected IS NOT NULL
	   )
	BEGIN
		DECLARE @DeadDate DATE, 
				@IsFinal BIT, 
				@RevisionNumber INT, 
				@OrganisationalUnitGuid UNIQUEIDENTIFIER,
				@DateDeclined DATE,
				@DateDeclinedReason NVARCHAR(MAX),
				@ContractGuid UNIQUEIDENTIFIER,
				@AgentContractGuid UNIQUEIDENTIFIER

		SELECT	@DeadDate = q.DeadDate, 
				@IsFinal = q.IsFinal,
				@RevisionNumber = q.RevisionNumber,
				@OrganisationalUnitGuid = ou.Guid,
				@DateDeclined = q.DateDeclinedToQuote,
				@DateDeclinedReason = q.DeclinedToQuoteReason,
				@ContractGuid = cct.Guid,
				@AgentContractGuid = act.Guid
		FROM	SSop.Quotes AS q
		JOIN	SCore.OrganisationalUnits AS ou ON (ou.ID = q.OrganisationalUnitID)
		JOIN    SSop.Contracts AS cct ON (cct.ID = q.ContractID)
		JOIN    SSop.Contracts AS act ON (act.ID = q.AgentContractID)
		WHERE	(q.Guid = @QuoteGuid)

		DECLARE	@ValidationResults SCore.ValidationResult

		INSERT @ValidationResults
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
		SELECT	qv.TargetGuid, qv.TargetType, qv.IsReadOnly, qv.IsHidden, qv.IsInvalid, qv.IsInformationOnly, qv.Message
		FROM	SSop.tvf_QuotesValidate(@QuoteGuid, @DateSent, @DeadDate, @DateRejected, @IsFinal, @RevisionNumber, @OrganisationalUnitGuid, @DateDeclined, @DateDeclinedReason, @ContractGuid, @AgentContractGuid) AS qv
		
		DECLARE	@ValidationMessage NVARCHAR(MAX) = SCore.GetValidationString(@ValidationResults)

		IF (@ValidationMessage <> N'')
		BEGIN			
			;THROW 60000, @ValidationMessage, 1
		END

		IF (EXISTS
				(
					SELECT	 1
					FROM	 @ValidationResults AS vr
					JOIN	SCore.EntityProperties AS ep ON (ep.Guid = vr.TargetGuid)
					WHERE	((vr.IsReadOnly = 1) OR (vr.IsHidden = 1))
						AND	(
								(ep.Name = N'DateSent' AND @DateSent IS NOT NULL)
							OR	(ep.Name = N'DateRejected' AND @DateRejected IS NOT NULL)
							OR	(ep.Name = N'DateAccepted' AND @DateAccepted IS NOT NULL)
							)
				)
			)
		BEGIN 
			;THROW 60000, N'You cannot change the Sent, Rejected or Accepted Date at the time, please check the state current of the quote.', 1
		END

		UPDATE	SSop.Quotes
		SET		DateSent = @DateSent,
				DateRejected = @DateRejected,
				DateAccepted = @DateAccepted
		WHERE	(Guid = @QuoteGuid);

	END;
END;



GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuoteItems]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteItems]
(
	@UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
    --WITH SCHEMABINDING
AS RETURN	
SELECT  qi.ID,
        qi.RowStatus,
        qi.Guid,
		qi.SortOrder,
		qi.Details,
		p.Code,
		qi.Quantity,
		qi.Net,
		qit.Vat,
		qit.Gross,
		qit.LineNet,
		qit.LineVat,
		qit.LineGross
FROM    SSop.QuoteItems qi
JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
JOIN	SProd.Products p ON (p.ID = qi.ProductId)	
WHERE   (qi.RowStatus NOT IN (0, 254))
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(qi.Guid, @UserId) oscr
			)
		)
	AND	(q.Guid = @ParentGuid)
UNION ALL 
SELECT	-2,
		1,
		'00000000-0000-0000-0000-000000000000',
		999,
		N'Total',
		N'',
		SUM(qi.Quantity),
		SUM(qi.Net),
		SUM(qit.Vat),
		SUM(qit.Gross),
		SUM(qit.LineNet),
		SUM(qit.LineVat),
		SUM(qit.LineGross)
FROM    SSop.QuoteItems qi
JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
WHERE   (qi.RowStatus NOT IN (0, 254))
	AND	(q.Guid = @ParentGuid)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Quote_JobsSummary]
--
GO
CREATE OR ALTER VIEW [SSop].[Quote_JobsSummary]
	--WITH SCHEMABINDING
AS
SELECT		MIN (qi.ID)							   AS ID,
			q.RowStatus,
			q.Guid								   AS QuoteGuid,
			q.Overview,
			--p.Guid								   AS UprnGuid,
			q.IsSubjectToNDA,
			SUM (qit.LineNet)					   AS Net,
			SUM (	CASE
						WHEN rs.Number = 1 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage1Fee,
			SUM (	CASE
						WHEN rs.Number = 2 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage2Fee,
			SUM (	CASE
						WHEN rs.Number = 3 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage3Fee,
			SUM (	CASE
						WHEN rs.Number = 4 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage4Fee,
			SUM (	CASE
						WHEN rs.Number = 5 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage5Fee,
			SUM (	CASE
						WHEN rs.Number = 6 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage6Fee,
			SUM (	CASE
						WHEN rs.Number = 7 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage7Fee,
			SUM (	CASE
						WHEN rs.Number = 99 THEN qit.LineNet
						ELSE 0
					END
				)								   AS PreConstructionStageFee,
			SUM (	CASE
						WHEN rs.Number = 999 THEN qit.LineNet
						ELSE 0
					END
				)								   AS ConstructionStageFee,
			ou.Guid								   AS OrganisationalUnitGuid,
			jt.Guid								   AS JobTypeGuid,
			--acc.Guid							   AS ClientAccountGuid,
			--ad.Guid								   AS ClientAddressGuid,
			--c.Guid								   AS ClientContactGuid,
			cr.Guid								   AS ContractGuid,
			--agent_acc.Guid						   AS AgentAccountGuid,
			--agent_ad.Guid						   AS AgentAddressGuid,
			--agent_c.Guid						   AS AgentContactGuid,
			'00000000-0000-0000-0000-000000000000' AS IdentityGuid,
			-1									   AS QuoteItemId,
			q.ExternalReference,
			SUM (qit.LineNet)					   AS AgreedFee,
			jt.Name								   AS JobType,
			q.DateAccepted,
			q.FeeCap,
			--proj.Guid							   AS ProjectGuid,
			ISNULL (   crs.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   )							   AS CurrentRibaStageGuid,
			ISNULL (   ars.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   )							   AS AppointedRibaStageGuid,
			q.ValueOfWork,
			acr.Guid							   AS AgentContractGuid
FROM		SSop.QuoteItems			  AS qi
JOIN		SSop.QuoteItemTotals	  AS qit ON (qit.ID				= qi.ID)
JOIN		SJob.RibaStages			  AS rs ON (rs.ID				= qi.ProvideAtStageID)
JOIN		SProd.Products			  AS p2 ON (p2.ID				= qi.ProductId)
JOIN		SJob.JobTypes			  AS jt ON (p2.CreatedJobType	= jt.ID)
JOIN		SSop.Quotes				  AS q ON (q.ID					= qi.QuoteId)
JOIN		SCore.OrganisationalUnits AS ou ON (ou.ID				= q.OrganisationalUnitID)
JOIN		SSop.Contracts			  AS cr ON (cr.ID				= q.ContractID)
JOIN		SSop.Contracts			  AS acr ON (acr.ID				= q.AgentContractID)
JOIN		SSop.EnquiryServices	  AS es ON (es.ID				= q.EnquiryServiceID)
JOIN		SSop.Enquiries			  AS e ON (e.ID					= es.EnquiryId)
JOIN		SJob.RibaStages			  AS crs ON (crs.ID				= e.CurrentProjectRibaStageID)
JOIN		SJob.RibaStages			  AS ars ON (ars.ID				= q.AppointmentFromRibaStageId)
--JOIN		SCrm.Accounts			  AS acc ON (acc.ID				= e.ClientAccountId)
--JOIN		SCrm.AccountAddresses	  AS ad ON (ad.ID				= e.ClientAddressId)
--JOIN		SCrm.AccountContacts	  AS c ON (c.ID					= e.ClientAccountContactId)
--JOIN		SCrm.Accounts			  AS agent_acc ON (agent_acc.ID = e.AgentAccountId)
--JOIN		SCrm.AccountAddresses	  AS agent_ad ON (agent_ad.ID	= e.AgentAddressId)
--JOIN		SCrm.AccountContacts	  AS agent_c ON (agent_c.ID		= e.AgentAccountContactId)
--JOIN		SJob.Properties			  AS p ON (p.ID					= e.PropertyId)
--JOIN		SSop.Projects			  AS proj ON (proj.ID			= e.ProjectId)
WHERE		(qi.RowStatus NOT IN (0, 254))
		AND (qi.Quantity			> 0)
		AND (qi.CreatedJobId		< 0)
		AND (qi.DoNotConsolidateJob = 0)
		AND (NOT EXISTS
	(
		SELECT	1
		FROM	SProd.Products AS prod2
		WHERE	(prod2.NeverConsolidate = 1)
			AND (qi.ProductId			= prod2.ID)
	)
			)
GROUP BY	q.RowStatus,
			q.Guid,
			q.Overview,
			--p.Guid,
			q.IsSubjectToNDA,
			jt.Guid,
			jt.Name,
			ou.Guid,
			--acc.Guid,
			--ad.Guid,
			--c.Guid,
			cr.Guid,
			--agent_acc.Guid,
			--agent_ad.Guid,
			--agent_c.Guid,
			q.ExternalReference,
			q.DateAccepted,
			q.FeeCap,
			--proj.Guid,
			crs.Guid,
			ars.Guid,
			q.ValueOfWork,
			q.AgentContractID,
			acr.Guid
UNION ALL
SELECT		qi.ID								  AS ID,
			q.RowStatus,
			q.Guid,
			q.Overview,
			--p.Guid,
			q.IsSubjectToNDA,
			qit.LineNet,
			CASE
				WHEN rs.Number = 1 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 2 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 3 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 4 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 5 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 6 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 7 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 99 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 999 THEN qit.LineNet
				ELSE 0
			END,
			ou.Guid,
			jt.Guid,
			--acc.Guid,
			--ad.Guid,
			--c.Guid,
			cr.Guid,
			--agent_acc.Guid,
			--agent_ad.Guid,
			--agent_c.Guid,
			'00000000-0000-0000-0000-000000000000',
			qi.ID,
			q.ExternalReference,
			--vow.Guid,
			qi.Net,
			jt.Name,
			q.DateAccepted,
			q.FeeCap,
			--proj.Guid							  AS ProjectGuid,
			ISNULL (   crs.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   ),
			ISNULL (   ars.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   ),
			q.ValueOfWork,
			acr.Guid
FROM		SSop.QuoteItems			  AS qi
JOIN		SSop.QuoteItemTotals	  AS qit ON (qit.ID				= qi.ID)
JOIN		SJob.RibaStages			  AS rs ON (rs.ID				= qi.ProvideAtStageID)
JOIN		SSop.Quotes				  AS q ON (q.ID					= qi.QuoteId)
JOIN		SProd.Products			  AS prod ON (prod.ID			= qi.ProductId)
JOIN		SJob.JobTypes			  AS jt ON (jt.ID				= prod.CreatedJobType)
JOIN		SCore.OrganisationalUnits AS ou ON (ou.ID				= q.OrganisationalUnitID)
JOIN		SSop.Contracts			  AS cr ON (cr.ID				= q.ContractID)
JOIN		SSop.Contracts			  AS acr ON (acr.ID				= q.AgentContractID)
JOIN		SSop.EnquiryServices	  AS es ON (es.ID				= q.EnquiryServiceID)
JOIN		SSop.Enquiries			  AS e ON (e.ID					= es.EnquiryId)
JOIN		SJob.RibaStages			  AS crs ON (crs.ID				= e.CurrentProjectRibaStageID)
JOIN		SJob.RibaStages			  AS ars ON (ars.ID				= q.AppointmentFromRibaStageId)
--JOIN		SCrm.Accounts			  AS acc ON (acc.ID				= e.ClientAccountId)
--JOIN		SCrm.AccountAddresses	  AS ad ON (ad.ID				= e.ClientAddressId)
--JOIN		SCrm.AccountContacts	  AS c ON (c.ID					= e.ClientAccountContactId)
--JOIN		SCrm.Accounts			  AS agent_acc ON (agent_acc.ID = e.AgentAccountId)
--JOIN		SCrm.AccountAddresses	  AS agent_ad ON (agent_ad.ID	= e.AgentAddressId)
--JOIN		SCrm.AccountContacts	  AS agent_c ON (agent_c.ID		= e.AgentAccountContactId)
--JOIN		SJob.Properties			  AS p ON (p.ID					= e.PropertyId)
--JOIN		SSop.Projects			  AS proj ON (proj.ID			= e.ProjectId)
WHERE		(qi.RowStatus NOT IN (0, 254))
		AND (qi.Quantity			  > 0)
		AND (qi.CreatedJobId		  < 0)
		AND
		  (
			  (prod.NeverConsolidate  = 1)
		   OR (qi.DoNotConsolidateJob = 1)
		  );
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuotesDataPills]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuotesDataPills]
  (
    @Guid                UNIQUEIDENTIFIER,
    @DateAccepted        DATE,
    @DateRejected        DATE,
	@ProjectGuid	     UNIQUEIDENTIFIER,
	@ContractGuid	     UNIQUEIDENTIFIER,
	@AgentContractGuid   UNIQUEIDENTIFIER
  )
RETURNS @DataPills TABLE
  (
    [ID]        [INT]        IDENTITY (1, 1) NOT NULL,
    [Label]     NVARCHAR(50) NOT NULL,
    [Class]     NVARCHAR(50) NOT NULL,
    [SortOrder] INT          NOT NULL
  )
AS
  BEGIN
	DECLARE	@IsSubjectToNDA BIT 

	SELECT	@IsSubjectToNDA = p.IsSubjectToNDA
	FROM	SSop.Projects AS p
	WHERE	(p.Guid = @ProjectGuid)


    IF (@IsSubjectToNDA = 1)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'NDA',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END

    -- Show that the quote is accepted.
    IF (@DateAccepted IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Accepted',	-- Label - nvarchar(50)
                  N'bg-success',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END

    IF (@DateRejected IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Rejected',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END

    

    -- Warn if the quote is accepted but jobs haven't been created. 
    IF (@DateAccepted IS NOT NULL)
      BEGIN
        DECLARE @JobCount INT

        SELECT
                @JobCount = COUNT(1)
        FROM
                SSop.Quote_JobsSummary js
        WHERE
                (js.QuoteGuid = @Guid)

        IF (@JobCount > 0)
          BEGIN
            INSERT @DataPills
                  (
                    Label,
                    Class,
                    SortOrder
                  )
            VALUES
                    (
                      CONVERT(NVARCHAR(50), @JobCount) + N' job(s) pending creation.',	-- Label - nvarchar(50)
                      N'bg-warning',	-- Class - nvarchar(50)
                      1		-- SortOrder - int
                    )
          END;
      END

	

	  --Finance Account On Hold
	  IF (EXISTS
			(
				SELECT 
						AC.AccountStatusID
				FROM 
					SSop.Quotes AS Q
				JOIN
					SSop.Quote_ExtendedInfo AS QE ON (Q.ID = QE.ID)
				JOIN 
					SCrm.Accounts AC ON (QE.FinanceAccountId = AC.ID)
				WHERE Q.Guid = @Guid AND AC.AccountStatusID = 4
			)	
		)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Credit Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END;

	    IF(@ContractGuid <> '00000000-0000-0000-0000-000000000000' OR @AgentContractGuid <> '00000000-0000-0000-0000-000000000000')
	   BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Contract In Place',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )


			--Get the EndDate + NextReviewDate when either contract field is set
			DECLARE @EndDate DATE,
					@NextReviewDate DATE;

			
			IF(@ContractGuid <> '00000000-0000-0000-0000-000000000000')
			BEGIN
				SELECT @EndDate = EndDate, 
					   @NextReviewDate = NextReviewDate
				FROM SSop.Contracts
				WHERE (Guid = @ContractGuid);

			END
			ELSE IF(@AgentContractGuid <> '00000000-0000-0000-0000-000000000000')
			BEGIN
				SELECT @EndDate = EndDate, 
					   @NextReviewDate = NextReviewDate
				FROM SSop.Contracts
				WHERE (Guid = @AgentContractGuid);
			END;

			--Check how many days are left before the contract expires.
			IF DATEDIFF(DAY, GETDATE(), @EndDate) <= 30
			BEGIN
				INSERT @DataPills
					  (
						Label,
						Class,
						SortOrder
					  )
				VALUES
						(
						  N'Contract Ending In ' + CONVERT(NVARCHAR(10), DATEDIFF(DAY, GETDATE(), @EndDate)) + N' Days',	-- Label - nvarchar(50)
						  N'bg-danger',	-- Class - nvarchar(50)
						  8		-- SortOrder - int
						)
			END

			--Check how many days before the contract needs reviewing. 
			IF DATEDIFF(DAY, GETDATE(), @NextReviewDate) <= 30
			BEGIN
				INSERT @DataPills
						  (
							Label,
							Class,
							SortOrder
						  )
				VALUES
						(
						  N'Contract Needs Reviewing By ' + CONVERT(NVARCHAR(10), @NextReviewDate, 23) ,	-- Label - nvarchar(50)
						  N'bg-danger',	-- Class - nvarchar(50)
						  9		-- SortOrder - int
						)
			END;
      END;

    RETURN
  END


GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[QuoteSectionTotals]
--
GO
CREATE OR ALTER VIEW [SSop].[QuoteSectionTotals]
        --WITH SCHEMABINDING
AS 
SELECT	qi.QuoteSectionId AS ID,
		CONVERT(DECIMAL(9, 2), ROUND(SUM(qit.LineNet), 2)) AS Net,
		CONVERT(DECIMAL(9, 2), ROUND(SUM(qit.LineVat), 2)) AS Vat,
		CONVERT(DECIMAL(9, 2), ROUND(SUM(qit.LineGross), 2)) AS Gross
FROM	SSop.QuoteItems qi
JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
WHERE	(qi.RowStatus NOT IN (0, 254))
GROUP BY qi.QuoteSectionId
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuoteSections]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteSections]
	(
		@UserId INT,
		@ParentGuid UNIQUEIDENTIFIER
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN SELECT		qs.ID,
					qs.RowStatus,
					qs.RowVersion,
					qs.Guid,
					qs.SortOrder,
					qs.Name,
					rs.Number AS RibaStage,
					qst.Net,
					qst.Gross
	   FROM			SSop.QuoteSections			  AS qs
	   JOIN			SSop.Quotes					  AS q ON (q.ID = qs.QuoteId)
	   LEFT JOIN	SSop.QuoteSectionTotals		  AS qst ON (qst.ID = qs.ID)
	   JOIN			SJob.RibaStages				  AS rs ON (rs.ID = qs.RibaStageId)
	   WHERE		(qs.RowStatus NOT IN (0, 254))
				AND (qs.ID		> 0)
AND	(EXISTS
			(
					SELECT
							1
					FROM
							SCore.ObjectSecurityForUser_CanRead(qs.Guid, @UserId) oscr
			)
		)
				AND (q.Guid		= @ParentGuid)
	   UNION ALL
	   SELECT		-2,
					1,
					q.RowVersion,
					q.Guid,
					999,
					N'Total',
					0,
					SUM (ISNULL (	qst.Net,
									0
								)
						),
					SUM (ISNULL (	qst.Gross,
									0
								)
						)
	   FROM			SSop.QuoteSections		AS qs
	   JOIN			SSop.Quotes				AS q ON (q.ID	  = qs.QuoteId)
	   LEFT JOIN	SSop.QuoteSectionTotals AS qst ON (qst.ID = qs.ID)
	   WHERE		(qs.RowStatus NOT IN (0, 254))
				AND (qs.ID		> 0)
				AND (q.Guid		= @ParentGuid)
		GROUP BY	q.RowVersion, q.Guid
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

