--
-- Create or alter function [SSop].[tvf_EnquiryServices]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiryServices]
(
	@UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
             --WITH SCHEMABINDING
AS RETURN	
SELECT  es.ID,
        es.RowStatus,
        es.RowVersion,
        es.Guid,
		jt.Name AS JobType,
		q.FullNumber AS Quote,
		esei.QuoteNet, 
		CONCAT(srs.Number, ' - ', srs.Description) AS StartRibaStage,
		CONCAT(ers.Number, ' - ', ers.Description) AS EndRibaStage,
		CASE 
			WHEN q.ID < 0 THEN N'No Quote'
			WHEN q.DateDeclinedToQuote IS NOT NULL THEN N'Declined To Quote.' --NEW [CBLD-592]
			ELSE qcf.QuoteStatus END AS QuoteStatus
FROM    SSop.EnquiryServices es
JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id = es.ID)
JOIN	SSop.Quotes q ON (q.ID = esei.QuoteId)
JOIN	SSop.Quote_CalculatedFields AS qcf ON (qcf.ID = q.ID)
JOIN	SJob.JobTypes jt ON (jt.ID = es.JobTypeId)
JOIN	SJob.RibaStages srs ON (srs.ID = es.StartRibaStageId)
JOIN	SJob.RibaStages ers ON (ers.ID = es.EndRibaStageId)
JOIN	SSop.Enquiries enq ON (enq.ID = es.EnquiryId) --NEW [CBLD-592]
WHERE   (es.RowStatus NOT IN (0, 254))
	AND	(q.RowStatus NOT IN (0, 254))
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(es.Guid, @UserId) oscr
			)
		)
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.Enquiries AS e
				WHERE	(e.Guid = @ParentGuid)
					AND	(e.ID = es.EnquiryId)
			)
		)
UNION ALL
SELECT  -1,
        CONVERT(tinyint, 1),
        null,
        '00000000-0000-0000-0000-000000000000',
		N'Total:' AS JobType,
		N'' AS Quote,
		SUM(esei.QuoteNet) AS QuoteNet, 
		N'' AS StartRibaStage,
		N'' AS EndRibaStage,
		N'' AS QuoteStatus
FROM    SSop.EnquiryServices es
JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id = es.ID)
WHERE   (es.RowStatus NOT IN (0, 254))
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.Enquiries AS e
				WHERE	(e.Guid = @ParentGuid)
					AND	(e.ID = es.EnquiryId)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_EnquiriesValidate]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiriesValidate]
	(
		@Guid UNIQUEIDENTIFIER,
		@RowStatus TINYINT,
		@PropertyGuid UNIQUEIDENTIFIER,
		@ClientAccountGuid UNIQUEIDENTIFIER,
		@ClientAddressGuid UNIQUEIDENTIFIER,
		@AgentAccountGuid UNIQUEIDENTIFIER,
		@AgentAddressGuid UNIQUEIDENTIFIER,
		@FinanceAccountGuid UNIQUEIDENTIFIER,
		@FinanceAddressGuid UNIQUEIDENTIFIER,
		@IsReadyForQuoteReview BIT,
		@DescriptionOfWorks NVARCHAR(MAX),
		@ValueOfWork DECIMAL(19, 2),
		@CurrentProjectRibaStageGuid UNIQUEIDENTIFIER,
		@PropertyNumber NVARCHAR(100),
		@PropertyPostCode NVARCHAR(30),
		@ClientAddressNumber NVARCHAR(100),
		@ClientAddressPostCode NVARCHAR(30),
		@AgentAddressNumber NVARCHAR(100),
		@AgentAddressPostCode NVARCHAR(30),
		@AgentName NVARCHAR(250),
		@ClientName NVARCHAR(250),
		@DeclinedToQuoteDate DATE,
		@DeclinedToQuoteReason NVARCHAR(4000),
		@KeyDates NVARCHAR(2000),
		@DeadDate DATE,
		@EnterNewClientDetails BIT,
		@EnterNewAgentDetails BIT,
		@EnterNewFinanceDetails BIT,
		@EnterNewStructureDetails BIT,
		@IsClientFinanceAccount BIT,
		@ProjectGuid UNIQUEIDENTIFIER,
		@ClientContactDisplayName NVARCHAR(250),
		@AgentContactDisplayName NVARCHAR(250),
		@FinanceContactDisplayName NVARCHAR(250),
		@ClientContactDetailType UNIQUEIDENTIFIER,
		@ClientContactDetailTypeName NVARCHAR(100),
		@ClientContactDetailTypeValue NVARCHAR(250),
		@AgentContactDetailType UNIQUEIDENTIFIER,
		@AgentContactDetailTypeName NVARCHAR(100),
		@AgentContactDetailTypeValue NVARCHAR(250),
		@FinanceContactDetailType UNIQUEIDENTIFIER,
		@FinanceContactDetailTypeName NVARCHAR(100),
		@FinanceContactDetailTypeValue NVARCHAR(250)
	)
RETURNS @ValidationResult TABLE
	(
		ID INT IDENTITY(1, 1) NOT NULL,
		TargetGuid UNIQUEIDENTIFIER NOT NULL DEFAULT ('00000000-0000-0000-0000-000000000000'),
		TargetType CHAR(1) NOT NULL DEFAULT (''),
		IsReadOnly BIT NOT NULL DEFAULT ((0)),
		IsHidden BIT NOT NULL DEFAULT ((0)),
		IsInvalid BIT NOT NULL DEFAULT ((0)),
		IsInformationOnly BIT NOT NULL DEFAULT ((0)),
		Message NVARCHAR(2000) NOT NULL DEFAULT ('')
	)
AS
BEGIN
	DECLARE @EntityPropertyGuid UNIQUEIDENTIFIER;

	/*
		Hide the Declinded to quote reason if there's no declined to quote date. 
	*/
	IF (@DeclinedToQuoteDate IS NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'DeclinedToQuoteReason';
	END;

	/*
		Hide the old key dates field if it wasn't populated. 
	*/
	IF (@KeyDates = N'')
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'KeyDates';
	END;

	/*
		Ensure a reason has been given if we've declined to quote. 
	*/
	IF (@DeclinedToQuoteDate IS NOT NULL)
   AND	(@DeclinedToQuoteReason = N'')
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				0,
				1,
				N'You must enter the reason why we declined to quote.'
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'DeclinedToQuoteReason';
	END;

	/*
		If there's both a declined to quote date and reason, lock these fields down. 
	*/
	IF (@DeclinedToQuoteDate IS NOT NULL)
   AND	(@DeclinedToQuoteReason <> N'')
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name NOT IN (N'DeclinedToQuoteDate', N'DeclinedToQuoteReason');
	END;

	/* 
		If there's a dead date. Lock everything down except that field. 
	*/
	IF (@DeadDate IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   <> N'DeadDate';
	END;

	/* Hide show manual property entry.  */
	IF (
		   @PropertyGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewStructureDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'PropertyNameNumber', N'PropertyAddressLine1', N'PropertyAddressLine2',
							   N'PropertyAddressLine3', N'PropertyTown', N'PropertyCountyId', N'PropertyPostCode',
							   N'PropertyCountryId'
							  
							  );
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'PropertyID');
	END;

	/*
		Ensure that if the user is manually entering the client/agent/finance details - along with contact details -
		that any field pertaining to the contact details are made compulsory once the "...ContactDisplayName" has been filled.
	*/

	--Client
	IF (
			@EnterNewClientDetails = 1 AND 
			@ClientContactDisplayName <> N'' AND 
			(
				@ClientContactDetailType = '00000000-0000-0000-0000-000000000000' OR
				@ClientContactDetailTypeName = N'' OR
				@ClientContactDetailTypeValue = N''
			)
		)
	BEGIN
	INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					0,
					1,
					N'Please enter contact details for client.'
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'ClientContactDetailType', N'ClientContactDetailTypeName',N'ClientContactDetailTypeValue', N'');

	END;


	--Agent
	IF (
			@EnterNewAgentDetails = 1 AND 
			@AgentContactDisplayName <> N'' AND
			(
				@AgentContactDetailType = '00000000-0000-0000-0000-000000000000' OR
				@AgentContactDetailTypeName = N'' OR
				@AgentContactDetailTypeValue = N''
			)
		)
	BEGIN
	INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					0,
					1,
					N'Please enter contact details for agent account.'
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'AgentContactDetailType', N'AgentContactDetailTypeName',N'AgentContactDetailTypeValue', N'');

	END;

	--Finance
	IF (
			@EnterNewFinanceDetails = 1 AND 
			@FinanceContactDisplayName <> N'' AND
			(
				@FinanceContactDetailType = '00000000-0000-0000-0000-000000000000' OR
				@FinanceContactDetailTypeName = N'' OR
				@FinanceContactDetailTypeValue = N''
			)
		)
	BEGIN
	INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					0,
					1,
					N'Please enter contact details for finance account.'
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceContactDetailType', N'FinanceContactDetailTypeName',N'FinanceContactDetailTypeValue', N'');

	END;

	/* Hide / Show Manual Client Entry */
	IF (
		   @ClientAccountGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewClientDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'ClientName';
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'ClientAccountID');
	END;

	/* Hide show manual client Address Entry */
	IF (
		   @ClientAddressGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewClientDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'ClientAddressNameNumber', N'ClientAddressLine1', N'ClientAddressLine2',
							   N'ClientAddressLine3', N'ClientAddressTown', N'ClientAddressCountyId',
							   N'ClientAddressPostCode', N'ClientAddressCountryId',
							    N'ClientContactDisplayName',N'ClientContactDetailType',N'ClientContactDetailTypeName',N'ClientContactDetailTypeValue' --CBLD-653
							  );
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'ClientAddressID', N'ClientAccountContactID');  
	END;

	/* Hide Show Manual Agent Entry */
	IF (
		   @AgentAccountGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewAgentDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'AgentName';
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'AgentAccountID');
	END;

	/* Hide show manual agent address entry */
	IF (
		   @AgentAddressGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewAgentDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'AgentAddressNameNumber', N'AgentAddressLine1', N'AgentAddressLine2',
							   N'AgentAddressLine3', N'AgentTown', N'AgentCountyId', N'AgentAddressPostCode',
							   N'AgentCountryId', N'AgentContactDisplayName', N'AgentContactDetailType', N'AgentContactDetailTypeName', N'AgentContactDetailTypeValue'
							  );
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'AgentAddressID', N'AgentAccountContactID');
	END;

	/* Hide show manual finance account entry */
	IF (@IsClientFinanceAccount = 1)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epg.Guid,
				N'G',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertyGroups AS epg
		JOIN	SCore.EntityTypes		   AS et ON (et.ID = epg.EntityTypeID)
		WHERE	(epg.Name = N'Finance Account Details')
			AND (et.Name  = N'Enquiries');
	END;
	ELSE
	BEGIN
		IF (
			   @FinanceAccountGuid <> '00000000-0000-0000-0000-000000000000'
			OR	@EnterNewFinanceDetails = 0
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name	   = N'FinanceAccountName';
		END;
		ELSE
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceAccountID');
		END;

		IF (
			   @FinanceAddressGuid <> '00000000-0000-0000-0000-000000000000'
			OR	@EnterNewFinanceDetails = 0
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceAddressNameNumber', N'FinanceAddressLine1', N'FinanceAddressLine2',
								   N'FinanceAddressLine3', N'FinanceTown', N'FinanceCountyId', N'FinancePostCode',
								   N'FinanceContactDisplayName', N'FinanceContactDetailType', N'FinanceContactDetailTypeName', N'FinanceContactDetailTypeValue'
								  );
		END;
		ELSE
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceAddressID', N'FinanceContactID');
		END;
	END;

	

	IF (@IsReadyForQuoteReview = 1)
		BEGIN
			IF (@DescriptionOfWorks = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'DescriptionOfWorks'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until there is a description of the works.'
					 );
			END;

			IF (@ValueOfWork = 0)
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'ValueOfWork'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until there is a value of work.'
					 );
			END;

			IF (@CurrentProjectRibaStageGuid = '00000000-0000-0000-0000-000000000000')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'CurrentProjectRibaStageId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until there is a current RIBA stage.'
					 );
			END;


			IF (@PropertyGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@PropertyNumber = N'')
		   AND	(@PropertyPostCode = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'PropertyId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until property details have been entered.'
					 );
			END;

			/*
				Don't allow the enquiry to be submitted for quoting until their is a client or agent. 
			*/
			IF (@ClientAccountGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@ClientName = N'')
		   AND	(@AgentAccountGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@AgentName = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'ClientAccountId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent account has been entered.'
					 );

				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'AgentAccountId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent account has been entered.'
					 );
			END;

			/*
				Don't allow the enquiry to be submitted for quoting until their is a client or agent. 
			*/
			IF (@ClientAddressGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@ClientAddressNumber = N'')
		   AND	(@ClientAddressPostCode = N'')
		   AND	(@AgentAddressGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@AgentAddressNumber = N'')
		   AND	(@AgentAddressPostCode = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'ClientAddressId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent address details have been entered.'
					 );

				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'AgentAddressId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent address details have been entered.'
					 );
			END;
		END;


	/*
		Check if there are quotes in existence. 
	*/
	DECLARE	@IsReadyForQuoteReviewGuid UNIQUEIDENTIFIER = SCore.GetEntityPropertyGuid(N'SSop', N'Enquiries', N'IsReadyForQuoteReview')
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.EnquiryServices AS es
		 JOIN	SSop.Enquiries		 AS e ON (e.ID = es.EnquiryId)
		 WHERE	(e.Guid = @Guid)
			AND (es.RowStatus NOT IN (0, 254))
			AND (EXISTS
			 (
				 SELECT 1
				 FROM	SSop.Quotes AS q
				 WHERE	(q.EnquiryServiceID = es.ID)
					AND (q.RowStatus NOT IN (0, 254))
			 )
				)
			AND (EXISTS
						(
							SELECT	1
							FROM	SCore.RecordHistory AS rh
							JOIN	SCore.EntityProperties ep ON (ep.ID = rh.EntityPropertyID)
							WHERE	(ep.Guid = @IsReadyForQuoteReviewGuid)
								AND	(rh.RowGuid = @Guid)
						)
					)
	 )
	   )
	BEGIN
		/*
			Prevent changes to 
				- Ready for Quote, ead Date and Declined to Quote date, 
				- Enquiry and Status Groups
				- Entering adhoc account or structure details. 
			after quotes have been created. 
		*/
		

		IF (EXISTS
		 (
			 SELECT 1
			 FROM	SSop.EnquiryServices AS es
			 JOIN	SSop.Enquiries		 AS e ON (e.ID = es.EnquiryId)
			 WHERE	(e.Guid = @Guid)
				AND (es.RowStatus NOT IN (0, 254))
		 )
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
			SELECT	epgfvv.Guid,		-- TargetGuid - uniqueidentifier
					epgfvv.TargetType,	-- TargetType - char(1)
					1,					-- IsReadOnly - bit
					0,					-- IsHidden - bit
					0,					-- IsInvalid - bit
					0,					-- IsInformationOnly - bit
					N''					-- Message - nvarchar(2000)
			FROM	SCore.EntityPropertiesGroupsForValidationV AS epgfvv
			WHERE	(epgfvv.EntityType = N'Enquiries')
				AND (epgfvv.Name NOT IN (N'Enquiry', N'Status'));

			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
			SELECT	epfvv.Guid,			-- TargetGuid - uniqueidentifier
					epfvv.TargetType,	-- TargetType - char(1)
					1,					-- IsReadOnly - bit
					1,					-- IsHidden - bit
					0,					-- IsInvalid - bit
					0,					-- IsInformationOnly - bit
					N''					-- Message - nvarchar(2000)
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	(epfvv.[Schema] = N'SSop')
				AND (epfvv.Hobt		= N'Enquiries')
				AND (epfvv.Name IN (N'EnterNewClientDetails', N'EnterNewStructureDetails', N'EnterNewAgentDetails',
									N'EnterNewFinanceDetails'
								   )
					);
		END;

		/* If any of the quotes have reached ceertain states, don't allow the enquiry to be changed. */
		IF (EXISTS
		 (
			 SELECT 1
			 FROM	SSop.EnquiryServices			 AS es
			 JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id	 = es.ID)
			 JOIN	SSop.Enquiries					 AS e ON (e.ID			 = es.EnquiryId)
			 JOIN	SSop.Quote_CalculatedFields		 AS qcf ON (esei.QuoteID = qcf.ID)
			 WHERE	(qcf.QuoteStatus IN (N'Sent', N'Accepted', N'Rejected', N'Complete'))
				AND (e.Guid = @Guid)
				AND	(es.RowStatus NOT IN (0, 254))
		 )
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
			SELECT	epgfvv.Guid,		-- TargetGuid - uniqueidentifier
					epgfvv.TargetType,	-- TargetType - char(1)
					1,					-- IsReadOnly - bit
					0,					-- IsHidden - bit
					0,					-- IsInvalid - bit
					0,					-- IsInformationOnly - bit
					N''					-- Message - nvarchar(2000)
			FROM	SCore.EntityPropertiesGroupsForValidationV AS epgfvv
			WHERE	(epgfvv.EntityType = N'Enquiries')
			AND (epgfvv.Name NOT IN (N'Status')) --Do not disable the "Status" group just yet.
		END;

		--Disable everything but the two chase date fields in the "Status" group
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				epfvv.TargetType,
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'IsReadyForQuoteReview', N'DeclinedToQuoteDate', N'DeadDate')
	END;



	RETURN;
END;

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_CurrentQuotes]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_CurrentQuotes]
(
	@UserId INT
)
RETURNS TABLE
     --WITH SCHEMABINDING
AS RETURN	
SELECT  q.ID,
        q.RowStatus,
        q.RowVersion,
        q.Guid,
		q.FullNumber AS Number,
		CASE WHEN q.DescriptionOfWorks <> N'' THEN LEFT(q.DescriptionOfWorks, 200) ELSE LEFT(q.Overview, 200) END AS Details, --[CBLD-640]
		--LEFT(q.Overview, 200) AS Details, 
		acc.Name + N' / ' + agent.Name AS Account,
		uprn.FormattedAddressComma,
		qcf.QuoteStatus,
		i.FullName AS QuotingConsultant,
		q.RevisionNumber,
		ou.Name AS OrganisationalUnitName
FROM    SSop.Quotes q
JOIN	SSop.Quote_CalculatedFields qcf ON (qcf.ID = q.ID)
JOIN	SCrm.Accounts acc ON (acc.ID = q.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = q.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = q.UprnId)
JOIN	SCore.Identities i ON (i.ID = q.QuotingConsultantId)
JOIN    SCore.OrganisationalUnits ou ON q.OrganisationalUnitID = ou.ID
WHERE   (q.RowStatus NOT IN (0, 254))
	AND	(q.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(q.Guid, @UserId) oscr
			)
		)
	AND	(
			(q.DateAccepted IS NULL)
			OR 
			(
				(q.DateAccepted IS NOT NULL)
				AND (EXISTS 
						(
							SELECT	1
							FROM	SSop.QuoteItems qi
							JOIN	SSop.QuoteSections qs ON (qs.ID = qi.QuoteSectionId)
							WHERE	(qs.QuoteID = q.ID)
								AND	(qi.RowStatus NOT IN (0, 254))
								AND	(qi.CreatedJobId < 0)
						)
					)
			)
		)
	AND	(q.DateRejected IS NULL)
	AND	(q.ExpiryDate > GETDATE())
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_ContractQuoteHistory]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_ContractQuoteHistory]
(
	@UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
     --WITH SCHEMABINDING
AS RETURN	
SELECT  q.ID,
        q.RowStatus,
        q.RowVersion,
        q.Guid,
		q.Number,
		q.Overview,
		qcf.QuoteStatus
FROM    SSop.Quotes q
JOIN	SSop.Quote_CalculatedFields qcf ON (qcf.ID = q.ID)
JOIN	SSop.Contracts c ON (c.ID = q.ContractID)
WHERE   (q.RowStatus NOT IN (0, 254))
	AND	(q.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(q.Guid, @UserId) oscr
			)
		)
	AND	(c.Guid = @ParentGuid)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SJob].[Job_FeeDrawdown]
--
GO
CREATE OR ALTER VIEW [SJob].[Job_FeeDrawdown] 
	    --WITH SCHEMABINDING
AS SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		CASE
				WHEN rs.Number = -1 THEN
					N'Fee Cap'
				ELSE
				CONVERT(NVARCHAR(10),
				rs.Number
				)
		END	  AS Stage,
		CASE
				WHEN rs.Number = -1 THEN
					N'Fee Cap'
				ELSE
				rs.Description
		END	  AS StageLabel,
		CASE rs.Number
				WHEN N'0' THEN
					(0 + ISNULL(Amendments.Stage0Change,
					0
					)
					)
				WHEN N'1' THEN
					(j.RibaStage1Fee + ISNULL(Amendments.Stage1Change,
					0
					)
					)
				WHEN N'2' THEN
					(j.RibaStage2Fee + ISNULL(Amendments.Stage2Change,
					0
					)
					)
				WHEN N'3' THEN
					(j.RibaStage3Fee + ISNULL(Amendments.Stage3Change,
					0
					)
					)
				WHEN N'4' THEN
					(j.RibaStage4Fee + ISNULL(Amendments.Stage4Change,
					0
					)
					)
				WHEN N'5' THEN
					(j.RibaStage5Fee + ISNULL(Amendments.Stage5Change,
					0
					)
					)
				WHEN N'6' THEN
					(j.RibaStage6Fee + ISNULL(Amendments.Stage6Change,
					0
					)
					)
				WHEN N'7' THEN
					(j.RibaStage7Fee + ISNULL(Amendments.Stage7Change,
					0
					)
					)
				WHEN N'99' THEN
					(j.PreConstructionStageFee + ISNULL(Amendments.PreConstructionStageChange,
					0
					)
					)
				WHEN N'999' THEN
					(j.ConstructionStageFee + ISNULL(Amendments.ConstructionStageChange,
					0
					)
					)
				ELSE
				(j.FeeCap + ISNULL(Amendments.FeeCapChange,
				0
				)
				)
		END	  AS Agreed,
		SUM(ISNULL(td.Net,
		0
		))	  AS Invoiced,
		CASE rs.Number
				WHEN N'0' THEN
					0
				WHEN N'1' THEN
					--j.RibaStage1Fee
					(j.RibaStage1Fee + ISNULL(Amendments.Stage1Change,0) )
				WHEN N'2' THEN
					--j.RibaStage2Fee
					(j.RibaStage2Fee + ISNULL(Amendments.Stage2Change,0))
				WHEN N'3' THEN
					--j.RibaStage3Fee
					(j.RibaStage3Fee + ISNULL(Amendments.Stage3Change,0))
				WHEN N'4' THEN
					--j.RibaStage4Fee
					(j.RibaStage4Fee + ISNULL(Amendments.Stage4Change,0))
				WHEN N'5' THEN
					--j.RibaStage5Fee
					(j.RibaStage5Fee + ISNULL(Amendments.Stage5Change,0))
				WHEN N'6' THEN
					--j.RibaStage6Fee
					(j.RibaStage6Fee + ISNULL(Amendments.Stage6Change,0))
				WHEN N'7' THEN
					--j.RibaStage7Fee
					(j.RibaStage7Fee + ISNULL(Amendments.Stage7Change,0))
				WHEN N'99' THEN
					(j.RibaStage7Fee + ISNULL(Amendments.PreConstructionStageChange,0))
				WHEN N'999' THEN
					(j.RibaStage7Fee + ISNULL(Amendments.ConstructionStageChange,0))
				ELSE
				j.FeeCap
		END - SUM(ISNULL(td.Net,
		0
		))	  AS Remaining,
		SUM(ISNULL(qi.NumberOfMeetings,
		0
		))
		+ CASE rs.Number
				WHEN N'0' THEN
					ISNULL(Amendments.MeetingsStage0Change,
					0
					)
				WHEN N'1' THEN
					ISNULL(Amendments.MeetingsStage1Change,
					0
					)
				WHEN N'2' THEN
					ISNULL(Amendments.MeetingsStage2Change,
					0
					)
				WHEN N'3' THEN
					ISNULL(Amendments.MeetingsStage3Change,
					0
					)
				WHEN N'4' THEN
					ISNULL(Amendments.MeetingsStage4Change,
					0
					)
				WHEN N'5' THEN
					ISNULL(Amendments.MeetingsStage5Change,
					0
					)
				WHEN N'6' THEN
					ISNULL(Amendments.MeetingsStage6Change,
					0
					)
				WHEN N'7' THEN
					ISNULL(Amendments.MeetingsStage7Change,
					0
					)
				WHEN N'99' THEN
					ISNULL(Amendments.PreConstructionMeetingChange,
					0
					)
				WHEN N'999' THEN
					ISNULL(Amendments.ConstructionMeetingChange,
					0
					)
				ELSE
					0
		END	 		
		AS QuotedMeetings,
		ISNULL(Meetings.MeetingTotal,
		0
		)	  AS CompletedMeetings,
		SUM(ISNULL(qi.NumberOfSiteVisits,
		0
		))	  
		
		+ CASE rs.Number
				WHEN N'0' THEN
					ISNULL(Amendments.VisitStage0Change,
					0
					)
				WHEN N'1' THEN
					ISNULL(Amendments.VisitStage1Change,
					0
					)
				WHEN N'2' THEN
					ISNULL(Amendments.VisitStage2Change,
					0
					)
				WHEN N'3' THEN
					ISNULL(Amendments.VisitStage3Change,
					0
					)
				WHEN N'4' THEN
					ISNULL(Amendments.VisitStage4Change,
					0
					)
				WHEN N'5' THEN
					ISNULL(Amendments.VisitStage5Change,
					0
					)
				WHEN N'6' THEN
					ISNULL(Amendments.VisitStage6Change,
					0
					)
				WHEN N'7' THEN
					ISNULL(Amendments.VisitStage7Change,
					0
					)
				WHEN N'99' THEN
					ISNULL(Amendments.PreConstructionVisitChange,
					0
					)
				WHEN N'999' THEN
					ISNULL(Amendments.ConstructionVisitChange,
					0
					)
				ELSE
					0
		END	 		
		
		AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		)	  AS CompletedSiteVisits,
		j.ID  AS JobId,
		rs.ID AS StageId,
		0 AS IsTotalHighlightRow
FROM
		SJob.Jobs AS j
CROSS JOIN
		SJob.RibaStages AS rs
LEFT JOIN
		SJob.Activities AS a ON (a.RibaStageId = rs.ID)
				AND (a.JobId = j.ID)
				AND	(a.RowStatus NOT IN (0, 254))
OUTER APPLY
		(
			SELECT
					td.Net *
							CASE
									WHEN tt.IsNegated = 1 THEN
										-1
									ELSE
									1
							END AS Net
			FROM
					SFin.TransactionDetails AS td
			JOIN
					SFin.Transactions AS t ON (t.ID = td.TransactionID)
			JOIN
					SFin.TransactionTypes AS tt ON (tt.ID = t.TransactionTypeID)
			WHERE
					(td.ActivityID = a.ID)
					AND (tt.IsBank = 0)
					AND (td.RowStatus NOT IN (0, 254))
					AND (t.RowStatus NOT IN (0, 254))
		) AS td
LEFT JOIN
		SSop.QuoteItems AS qi ON (qi.CreatedJobId = j.ID)
			AND	(qi.ProvideAtStageID = rs.ID)
			AND (qi.RowStatus NOT IN (0, 254))

OUTER APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change)		   AS Stage0Change,
					SUM(fa.RibaStage1Change)		   AS Stage1Change,
					SUM(fa.RibaStage2Change)		   AS Stage2Change,
					SUM(fa.RibaStage3Change)		   AS Stage3Change,
					SUM(fa.RibaStage4Change)		   AS Stage4Change,
					SUM(fa.RibaStage5Change)		   AS Stage5Change,
					SUM(fa.RibaStage6Change)		   AS Stage6Change,
					SUM(fa.RibaStage7Change)		   AS Stage7Change,
					SUM(fa.PreConstructionStageChange) AS PreConstructionStageChange,
					SUM(fa.ConstructionStageChange)	   AS ConstructionStageChange,
					SUM(fa.FeeCapChange)			   AS FeeCapChange, 
					SUM(fa.RibaStage0MeetingChange)	   AS MeetingsStage0Change,
					SUM(fa.RibaStage1MeetingChange)	   AS MeetingsStage1Change,
					SUM(fa.RibaStage2MeetingChange)	   AS MeetingsStage2Change,
					SUM(fa.RibaStage3MeetingChange)	   AS MeetingsStage3Change,
					SUM(fa.RibaStage4MeetingChange)	   AS MeetingsStage4Change,
					SUM(fa.RibaStage5MeetingChange)	   AS MeetingsStage5Change,
					SUM(fa.RibaStage6MeetingChange)	   AS MeetingsStage6Change,
					SUM(fa.RibaStage7MeetingChange)	   AS MeetingsStage7Change,
					SUM(fa.PreConstructionStageMeetingChange) AS PreConstructionMeetingChange,
					SUM(fa.ConstructionStageMeetingChange) AS ConstructionMeetingChange,
					SUM(fa.RibaStage0VisitChange)	   AS VisitStage0Change,
					SUM(fa.RibaStage1VisitChange)	   AS VisitStage1Change,
					SUM(fa.RibaStage2VisitChange)	   AS VisitStage2Change,
					SUM(fa.RibaStage3VisitChange)	   AS VisitStage3Change,
					SUM(fa.RibaStage4VisitChange)	   AS VisitStage4Change,
					SUM(fa.RibaStage5VisitChange)	   AS VisitStage5Change,
					SUM(fa.RibaStage6VisitChange)	   AS VisitStage6Change,
					SUM(fa.RibaStage7VisitChange)	   AS VisitStage7Change,
					SUM(fa.PreConstructionStageVisitChange) AS PreConstructionVisitChange,
					SUM(fa.ConstructionStageVisitChange) AS ConstructionVisitChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
					AND (ja.RibaStageId = rs.ID)
		) AS Meetings
WHERE
		(rs.ID > 0)
		AND (
				(
						(rs.IsRealStage = 1)
						AND (
								(j.PreConstructionStageFee = 0)
								AND (j.ConstructionStageFee = 0)
						)
				)
				OR (
						(rs.IsRealStage = 0)
						AND (
								(j.PreConstructionStageFee <> 0)
								OR (j.ConstructionStageFee <> 0)
						)
				)
		)
GROUP BY
		rs.Number,
		rs.Description,
		rs.ID,
		j.RibaStage1Fee,
		j.RibaStage2Fee,
		j.RibaStage3Fee,
		j.RibaStage4Fee,
		j.RibaStage5Fee,
		j.RibaStage6Fee,
		j.RibaStage7Fee,
		j.PreConstructionStageFee,
		j.ConstructionStageFee,
		j.FeeCap,
		j.RowStatus,
		j.Guid,
		j.ID,
		Amendments.FeeCapChange,
		Amendments.Stage0Change,
        Amendments.Stage1Change,
        Amendments.Stage2Change,
        Amendments.Stage3Change,
        Amendments.Stage4Change,
        Amendments.Stage5Change,
        Amendments.Stage6Change,
        Amendments.Stage7Change,
        Amendments.PreConstructionStageChange,
        Amendments.ConstructionStageChange,
        Amendments.FeeCapChange,
        Amendments.MeetingsStage0Change,
        Amendments.MeetingsStage1Change,
        Amendments.MeetingsStage2Change,
        Amendments.MeetingsStage3Change,
        Amendments.MeetingsStage4Change,
        Amendments.MeetingsStage5Change,
        Amendments.MeetingsStage6Change,
        Amendments.MeetingsStage7Change,
        Amendments.PreConstructionMeetingChange,
        Amendments.ConstructionMeetingChange,
        Amendments.VisitStage0Change,
        Amendments.VisitStage1Change,
        Amendments.VisitStage2Change,
        Amendments.VisitStage3Change,
        Amendments.VisitStage4Change,
        Amendments.VisitStage5Change,
        Amendments.VisitStage6Change,
        Amendments.VisitStage7Change,
        Amendments.PreConstructionVisitChange,
        Amendments.ConstructionVisitChange,
		Meetings.MeetingTotal,
		Meetings.SiteVisitTotal
UNION ALL
SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		N'Total (ex. Fee Cap.)',
		N'Total (ex. Fee Cap.)',
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee
		+ ISNULL(Amendments.TotalChange,
		0
		),
		ISNULL(jf.InvoicedValue,
		0
		),
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee
		+ ISNULL(Amendments.TotalChange,
		0
		) - ISNULL(jf.InvoicedValue,
		0
		),
		ISNULL(Quoted.Meetings,
		0
		) + ISNULL(Amendments.TotalMeetingChange, 0) AS QuotedMeetings,
		ISNULL(Meetings.MeetingTotal,
		0
		) AS CompletedMeetings,
		ISNULL(Quoted.SiteVisits,
		0
		) + ISNULL(Amendments.TotalVisitChange, 0) AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		) AS CompletedSiteVisits,
		j.ID,
		-2,
		1
FROM
		SJob.Jobs AS j
LEFT JOIN
		SJob.JobFinance AS jf ON (jf.ID = j.ID)
CROSS APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change + fa.RibaStage1Change + fa.RibaStage2Change + fa.RibaStage3Change + fa.RibaStage4Change
					+ fa.RibaStage5Change + fa.RibaStage6Change + fa.RibaStage7Change + fa.PreConstructionStageChange
					+ fa.ConstructionStageChange
					) AS TotalChange,
					SUM(fa.RibaStage0MeetingChange + fa.RibaStage1MeetingChange + fa.RibaStage2MeetingChange + fa.RibaStage3MeetingChange
					+ fa.RibaStage4MeetingChange + fa.RibaStage5MeetingChange + fa.RibaStage6MeetingChange + fa.RibaStage7MeetingChange
					+ fa.PreConstructionStageMeetingChange + fa.ConstructionStageMeetingChange) AS TotalMeetingChange,
					sum (fa.RibaStage0VisitChange + fa.RibaStage1VisitChange + fa.RibaStage2VisitChange + fa.RibaStage3VisitChange
					+ fa.RibaStage4VisitChange + fa.RibaStage5VisitChange + fa.RibaStage6VisitChange + fa.RibaStage7VisitChange
					+ fa.PreConstructionStageVisitChange + fa.ConstructionStageVisitChange)
					AS TotalVisitChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
		) AS Meetings
OUTER APPLY
		(
			SELECT
					SUM(qi.NumberOfMeetings)   Meetings,
					SUM(qi.NumberOfSiteVisits) SiteVisits
			FROM
					SSop.QuoteItems AS qi
			
			WHERE
					(qi.CreatedJobId = j.ID)
		) AS Quoted
UNION ALL
SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		N'Total (inc. Fee Cap)',
		N'Total (inc. Fee Cap)',
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee + j.FeeCap
		+ ISNULL(Amendments.TotalChange,
		0
		),
		ISNULL(jf.InvoicedValue,
		0
		),
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee + j.FeeCap
		+ ISNULL(Amendments.TotalChange,
		0
		) - ISNULL(jf.InvoicedValue,
		0
		),
		ISNULL(Quoted.Meetings,
		0
		) + ISNULL(Amendments.TotalMeetingChange, 0) AS QuotedMeetings,
		ISNULL(Meetings.MeetingTotal,
		0
		) AS CompletedMeetings,
		ISNULL(Quoted.SiteVisits,
		0
		) + ISNULL(Amendments.TotalVisitChange, 0) AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		) AS CompletedSiteVisits,
		j.ID,
		-3,
		1
FROM
		SJob.Jobs AS j
LEFT JOIN
		SJob.JobFinance AS jf ON (jf.ID = j.ID)
CROSS APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change + fa.RibaStage1Change + fa.RibaStage2Change + fa.RibaStage3Change + fa.RibaStage4Change
					+ fa.RibaStage5Change + fa.RibaStage6Change + fa.RibaStage7Change + fa.PreConstructionStageChange
					+ fa.ConstructionStageChange + fa.FeeCapChange
					) AS TotalChange,
					SUM(fa.RibaStage0MeetingChange + fa.RibaStage1MeetingChange + fa.RibaStage2MeetingChange + fa.RibaStage3MeetingChange
					+ fa.RibaStage4MeetingChange + fa.RibaStage5MeetingChange + fa.RibaStage6MeetingChange + fa.RibaStage7MeetingChange
					+ fa.PreConstructionStageMeetingChange + fa.ConstructionStageMeetingChange) AS TotalMeetingChange,
					sum (fa.RibaStage0VisitChange + fa.RibaStage1VisitChange + fa.RibaStage2VisitChange + fa.RibaStage3VisitChange
					+ fa.RibaStage4VisitChange + fa.RibaStage5VisitChange + fa.RibaStage6VisitChange + fa.RibaStage7VisitChange
					+ fa.PreConstructionStageVisitChange + fa.ConstructionStageVisitChange)
					AS TotalVisitChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
		) AS Meetings
OUTER APPLY
		(
			SELECT
					SUM(qi.NumberOfMeetings)   Meetings,
					SUM(qi.NumberOfSiteVisits) SiteVisits

			FROM
					SSop.QuoteItems AS qi
			WHERE
					(qi.CreatedJobId = j.ID)
				AND	(qi.RowStatus NOT IN (0, 254))
		) AS Quoted
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_JobFeeDrawdown]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_JobFeeDrawdown]
	(
		@UserId INT,
		@ParentGuid UNIQUEIDENTIFIER
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN SELECT	j.RowStatus,
				j.Guid,
				j.Stage,
				j.StageLabel,
				j.Agreed,
				j.Invoiced,
				j.Remaining,
				CONVERT(INT, j.QuotedMeetings) QuotedMeetings,
				j.CompletedMeetings,
				CONVERT(INT, j.QuotedSiteVisits) QuotedSiteVisits,
				j.CompletedSiteVisits,
				j.IsTotalHighlightRow
	   FROM		SJob.Job_FeeDrawdown AS j
	   WHERE	(j.Guid = @ParentGuid)
			AND	(EXISTS
			(
				SELECT	1
				FROM	SCore.ObjectSecurityForUser_CanRead (j.guid, @UserId) oscr
			)
		)

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Project_ExtendedInfo]
--
GO
CREATE OR ALTER VIEW	[SSop].[Project_ExtendedInfo]
    --WITH SCHEMABINDING
AS
SELECT	proj.Id,
		proj.RowStatus,
		proj.RowVersion,
		proj.Guid,
		ISNULL(enq.Count, 0) AS EnquiriesCount,
		ISNULL(quote.Count, 0) AS QuotesCount,
		ISNULL(quote.Total, 0) AS QuotesTotalValue,
		ISNULL(quote.AcceptedTotal, 0) AS AcceptedQuotesTotalValue,
		ISNULL(quote.AcceptedCount, 0) AS AcceptedQuotesCount,
		ISNULL(quote.RejectedTotal, 0) AS RejectedQuotesTotalValue,
		ISNULL(quote.RejectedCount, 0) AS RejectedQuotesCount,
		ISNULL(quote.PendingTotal, 0) AS PendingQuotesTotelValue,
		ISNULL(quote.PendingCount, 0) AS PendingQuotesCount,
		ISNULL(job.Count, 0) AS JobsCount,
		ISNULL(job.AgreedFeesTotal, 0) AS JobsTotalAgreedFeesTotal,
		ISNULL(job.InvoicedFeesTotal, 0) AS JobsTotalInvoicedFeesTotal,
		ISNULL(job.RemainingFeesTotal, 0) AS JobsTotalRemainingFeesTotal,
		ISNULL(job.CompletedCount, 0) AS JobsCompletedCount,
		ISNULL(job.CompletedAgreedFeesTotal, 0) AS JobsCompletedAgreedFeesTotal, 
		ISNULL(job.CompletedInvoicedFeesTotal, 0) AS JobsCompletedInvoicedFeesTotal,
		ISNULL(job.CompletedUnInvoicedFeesTotal, 0) AS JobsCompletedUninvoicesFeesTotal,
		ISNULL(job.ActiveCount, 0) AS JobsActiveCount,
		ISNULL(job.ActiveAgreedFeesTotal, 0) AS JobsActiveAgreedFeesTotal,
		ISNULL(job.ActiveInvoicedFeesTotal, 0) AS JobsActiveInvoicedFeesTotal,
		ISNULL(job.ActiveRemainingFeesTotal, 0) AS JobsActiveRemainingFeesTotal,
		ISNULL(job.CancelledCount, 0) AS JobsCancelledCount,
		ISNULL(job.CancelledAgreedFeesTotal, 0) AS JobsCancelledAgreedFeesTotal,
		ISNULL(job.CancelledInvoicedFeesTotal, 0) AS JobsCancelledInvoicedFeesTotal,
		ISNULL(job.CancelledUnInvoicedFeesTotal, 0) AS JobsCancelledUninvoicedFeesTotal,
		ISNULL(job.PercentageCompleted, 0) AS PercentageCompleted,
		ISNULL(job.PercentageAchievableRevenueAchieved, 0) AS PercentageAchievableRevenueAchieved,
		pl.ListLabel
FROM	SSop.Projects proj
JOIN	SSop.ProjectsList AS pl ON (pl.ID = proj.ID)
OUTER APPLY 
(
	SELECT	COUNT(1) AS [Count]
	FROM	SSop.Enquiries e
	WHERE	(e.ProjectId = proj.ID)
		AND	(e.ProjectId > 0)
) AS enq
OUTER APPLY 
(
	SELECT	COUNT(1) AS [Count],
			SUM(qstt.Net) AS Total,
			SUM(CASE WHEN q.DateAccepted IS NOT NULL THEN qstt.Net ELSE 0 END) AS AcceptedTotal,
			SUM(CASE WHEN q.DateAccepted IS NOT NULL THEN 1 ELSE 0 END) AS AcceptedCount,
			SUM(CASE WHEN q.DateRejected IS NOT NULL THEN qstt.Net ELSE 0 END) AS RejectedTotal,
			SUM(CASE WHEN q.DateRejected IS NOT NULL THEN 1 ELSE 0 END) AS RejectedCount,
			SUM(CASE WHEN q.DateSent IS NOT NULL AND q.DateAccepted IS NULL AND q.DateRejected IS NULL THEN qstt.Net ELSE 0 END) AS PendingTotal,
			SUM(CASE WHEN q.DateSent IS NOT NULL AND q.DateAccepted IS NULL AND q.DateRejected IS NULL THEN 1 ELSE 0 END) AS PendingCount
	FROM	SSop.Quotes q
	OUTER APPLY
	(
		SELECT	SUM(qst.Net) AS Net
		FROM	SSop.QuoteSections qs  
		JOIN	SSop.QuoteSectionTotals qst ON (qst.ID = qs.ID)
		WHERE	(qs.QuoteId = q.ID)
			AND	(qs.RowStatus NOT IN (0, 254))
	) qstt
	WHERE	(q.ProjectId = proj.ID)
		AND	(q.ProjectId > 0)
		AND	(q.RowStatus NOT IN (0, 254))
		
	GROUP BY	q.ProjectId
) AS quote
OUTER APPLY 
(
	SELECT	COUNT(1) AS [Count],
			SUM(fees.Agreed) AS AgreedFeesTotal,
			SUM(fees.Invoiced) AS InvoicedFeesTotal,
			SUM(fees.Remaining) AS RemainingFeesTotal,
			SUM(CASE WHEN j.IsComplete = 1 THEN 1 ELSE 0 END) AS CompletedCount,
			SUM(CASE WHEN j.IsComplete = 1 THEN fees.Agreed ELSE 0 END) AS CompletedAgreedFeesTotal,
			SUM(CASE WHEN j.IsComplete = 1 THEN fees.Invoiced ELSE 0 END) AS CompletedInvoicedFeesTotal,
			SUM(CASE WHEN j.IsComplete = 1 THEN fees.Remaining ELSE 0 END) AS CompletedUnInvoicedFeesTotal,
			SUM(CASE WHEN j.IsActive = 1 THEN 1 ELSE 0 END) AS ActiveCount,
			SUM(CASE WHEN j.IsActive = 1 THEN fees.Agreed ELSE 0 END) AS ActiveAgreedFeesTotal,
			SUM(CASE WHEN j.IsActive = 1 THEN fees.Invoiced ELSE 0 END) AS ActiveInvoicedFeesTotal,
			SUM(CASE WHEN j.IsActive = 1 THEN fees.Remaining ELSE 0 END) AS ActiveRemainingFeesTotal,
			SUM(CASE WHEN j.IsCancelled = 1 THEN 1 ELSE 0 END) AS CancelledCount,
			SUM(CASE WHEN j.IsCancelled = 1 THEN fees.Agreed ELSE 0 END) AS CancelledAgreedFeesTotal,
			SUM(CASE WHEN j.IsCancelled = 1 THEN fees.Invoiced ELSE 0 END) AS CancelledInvoicedFeesTotal,
			SUM(CASE WHEN j.IsCancelled = 1 THEN fees.Remaining ELSE 0 END) AS CancelledUnInvoicedFeesTotal,
			CASE WHEN (SUM(CASE WHEN j.IsCancelled = 0 THEN 1 ELSE 0 END) > 0) THEN   SUM(CASE WHEN j.IsComplete = 1 THEN 1 ELSE 0 END) / SUM(CASE WHEN j.IsCancelled = 0 THEN 1 ELSE 0 END) * 100 ELSE 0 END AS PercentageCompleted,
			CASE WHEN SUM(fees.Agreed) > 0 THEN (SUM(fees.Invoiced) / (SUM(CASE WHEN j.IsCancelled = 0 THEN fees.Agreed ELSE 0 END) + SUM(CASE WHEN j.IsCancelled = 0 THEN fees.Invoiced ELSE 0 END))) * 100 ELSE 0 END AS PercentageAchievableRevenueAchieved
	FROM	SJob.Jobs j
	OUTER APPLY	
	(
		SELECT	jfd.Agreed,
				jfd.Invoiced, 
				jfd.Remaining
		FROM	SJob.Job_FeeDrawdown jfd 
		WHERE	(j.id = jfd.ID)
			AND	(jfd.Stage = N'Total (ex. Fee Cap.)')
	) AS fees
	WHERE	(j.ProjectId = proj.ID)
		AND	(j.ProjectId > 0)
		AND	(j.RowStatus NOT IN (0, 254))
	GROUP BY	j.ProjectId
) AS job

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SJob].[Job_ExtendedInfo]
--
GO
CREATE OR ALTER VIEW	[SJob].[Job_ExtendedInfo]
    --WITH SCHEMABINDING
AS
SELECT	j.Id,
		j.RowStatus,
		j.RowVersion,
		j.Guid,
		ISNULL(QuoteDetail.Guid, '00000000-0000-0000-0000-000000000000') AS QuoteGuid
FROM	SJob.Jobs j 
OUTER APPLY
(
	SELECT	q.ID,
			q.Guid
	FROM	SSop.Quotes q
	WHERE	(EXISTS
				(
					SELECT	1
					FROM	SSop.QuoteItems qi
					WHERE	(qi.QuoteId = q.Id)
						AND	(qi.CreatedJobId = j.ID)

				)
			)
) QuoteDetail
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SJob].[GetJobSignatoryInfo]
--
GO
CREATE OR ALTER VIEW [SJob].[GetJobSignatoryInfo]
--WITH SCHEMABINDING
AS
SELECT		j.ID,
			j.RowStatus,
			j.RowVersion,
			ISNULL (   QuoteDetail.EnquiryGuid,
					   '00000000-0000-0000-0000-000000000000'
				   ) AS EnquiryGuid,
			ISNULL (   QuoteDetail.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   ) AS QuoteGuid,
			j.Guid	 AS JobGuid,
			jt.Name JobTypeName,
			QuoteDetail.FullName,
			QuoteDetail.UserGuid,
			QuoteDetail.EmailAddress,
			QuoteDetail.JobTitle,
			QuoteDetail.IsActive,
			ISNULL (   QuoteDetail.Signature,
					   0x
				   ) AS BinarySignature
FROM		SJob.Jobs AS j
JOIN		SJob.JobTypes		 AS jt ON (jt.ID = j.JobTypeId)
OUTER APPLY
			(
				SELECT	q.ID,
						q.Guid,
						q.EnquiryServiceID,
						e.Guid AS EnquiryGuid,
						i.Guid AS UserGuid,
						i.EmailAddress,
						i.JobTitle,
						i.FullName,
						I.IsActive,
						i.Signature
				FROM	SSop.Quotes AS q
				LEFT JOIN	SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
				LEFT JOIN	SSop.Enquiries		 AS e ON (e.ID	 = es.EnquiryId) 
				LEFT JOIN	SCore.Identities	 AS i ON (i.ID	 = e.SignatoryIdentityId)
				WHERE	(EXISTS
					(
						SELECT	1
						FROM	SSop.QuoteItems AS qi
						WHERE	(qi.QuoteId		 = q.ID)
							AND (qi.CreatedJobId = j.ID)
					)
						)
			)		  AS QuoteDetail
;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

